"use client";

import React, { useState, useEffect } from 'react';
import { Sidebar } from '@/components/Sidebar';
import { ChatInterface } from '@/components/ChatInterface';
import { api, ChatSession } from '@/lib/api';

import { SettingsModal } from '@/components/SettingsModal';
import { IngestModal } from '@/components/IngestModal';
import { ApiKeyModal } from '@/components/ApiKeyModal';
import { AnimatePresence } from 'framer-motion';
import { NotificationProvider, useNotification } from '@/context/NotificationContext';

export default function Home() {
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isIngestOpen, setIsIngestOpen] = useState(false);
  const [isApiKeyOpen, setIsApiKeyOpen] = useState(false);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  
  // Chat State
  const [chats, setChats] = useState<ChatSession[]>([]);
  const [currentChatId, setCurrentChatId] = useState<string | null>(null);

  useEffect(() => {
    loadChats();
  }, []);

  const loadChats = async () => {
    try {
      const chatList = await api.getChats();
      setChats(chatList);
      
      // Do not auto-select recent chat. Begin with new chat interface.
      // If chats exist, they are loaded in sidebar, but main view is empty state.
    } catch (err) {
      console.error("Failed to load chats:", err);
    }
  };

  const handleCreateChat = async () => {
    try {
      const newChat = await api.createChat();
      setChats(prev => [newChat, ...prev]);
      setCurrentChatId(newChat.id);
      return newChat.id;
    } catch (err) {
      console.error("Failed to create chat:", err);
      return null;
    }
  };



  const handleRenameChat = async (id: string, newTitle: string) => {
    try {
      await api.renameChat(id, newTitle);
      setChats(prev => prev.map(c => c.id === id ? { ...c, title: newTitle } : c));
    } catch (err) {
      console.error("Failed to rename chat:", err);
    }
  };

  return (
    <NotificationProvider>
      <HomeContent 
          isSettingsOpen={isSettingsOpen} setIsSettingsOpen={setIsSettingsOpen}
          isIngestOpen={isIngestOpen} setIsIngestOpen={setIsIngestOpen}
          isApiKeyOpen={isApiKeyOpen} setIsApiKeyOpen={setIsApiKeyOpen}
          isSidebarCollapsed={isSidebarCollapsed} setIsSidebarCollapsed={setIsSidebarCollapsed}
          chats={chats} setChats={setChats}
          currentChatId={currentChatId} setCurrentChatId={setCurrentChatId}
          onRenameChat={handleRenameChat}
          onCreateChat={handleCreateChat}
          loadChats={loadChats}
      />
    </NotificationProvider>
  );
}

// Sub-component to consume Context
function HomeContent({
    isSettingsOpen, setIsSettingsOpen,
    isIngestOpen, setIsIngestOpen,
    isApiKeyOpen, setIsApiKeyOpen,
    isSidebarCollapsed, setIsSidebarCollapsed,
    chats, setChats,
    currentChatId, setCurrentChatId,
    onRenameChat, onCreateChat, loadChats
}: any) {
    const { showNotification } = useNotification();

    const handleDeleteChat = async (id: string) => {
        showNotification({
            type: 'confirm',
            title: 'Delete Chat',
            message: 'Are you sure you want to delete this chat? This action cannot be undone.',
            confirmText: 'Delete',
            onConfirm: async () => {
                try {
                    await api.deleteChat(id);
                    setChats((prev: ChatSession[]) => prev.filter(c => c.id !== id));
                    
                    if (currentChatId === id) {
                        setCurrentChatId(null);
                        // We can verify if we need to loadChats or just pick one locally
                        // But calling loadChats from parent is safe
                        loadChats();
                    }
                    
                    showNotification({
                        type: 'success',
                        title: 'Chat Deleted',
                        message: 'The chat session has been successfully removed.'
                    });
                } catch (err) {
                    console.error("Failed to delete chat:", err);
                    showNotification({
                        type: 'error',
                        title: 'Deletion Failed',
                        message: 'Could not delete the chat. Please try again.'
                    });
                }
            }
        });
    };

    const handleChatUpdated = (id: string, updates: any) => {
        setChats((prev: ChatSession[]) => prev.map(c => c.id === id ? { ...c, ...updates } : c));
    };

    return (
      <main className="flex h-screen bg-black text-white overflow-hidden relative selection:bg-primary/30 selection:text-white">
        {/* Background Gradient */}
        <div className="absolute inset-0 z-0 bg-purple-glow opacity-30 pointer-events-none" />
        
        {/* Sidebar */}
        <div className="z-10 relative">
           <Sidebar 
              isCollapsed={isSidebarCollapsed}
              onToggle={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
              onOpenSettings={() => setIsSettingsOpen(true)}
              onOpenIngest={() => setIsIngestOpen(true)}
              onOpenApiKeys={() => setIsApiKeyOpen(true)}
              
              chats={chats}
              currentChatId={currentChatId}
              onSelectChat={setCurrentChatId}
              onCreateChat={onCreateChat}
              onDeleteChat={handleDeleteChat}
              onRenameChat={onRenameChat}
           />
        </div>

        {/* Main Chat Area */}
        <div className="flex-1 z-10 relative flex flex-col h-full bg-[#050505]/50 backdrop-blur-sm">
           <ChatInterface 
              chatId={currentChatId} 
              onChatUpdated={handleChatUpdated}
              onCreateSession={onCreateChat}
           />
        </div>

        {/* Modals */}
        <AnimatePresence>
          {isSettingsOpen && (
            <SettingsModal 
              isOpen={isSettingsOpen} 
              onClose={() => setIsSettingsOpen(false)} 
            />
          )}
          {isIngestOpen && (
            <IngestModal 
              isOpen={isIngestOpen} 
              onClose={() => setIsIngestOpen(false)} 
            />
          )}
          {isApiKeyOpen && (
            <ApiKeyModal 
              isOpen={isApiKeyOpen} 
              onClose={() => setIsApiKeyOpen(false)} 
            />
          )}
        </AnimatePresence>
      </main>
    );
}

import React, { useState, useEffect } from 'react';
import { X, Key, Check, Loader2, Trash2, Zap, CheckCircle } from 'lucide-react';
import { api } from '@/lib/api';
import { cn } from '@/lib/utils';
import { motion } from 'framer-motion';
import { useNotification } from '@/context/NotificationContext';

interface ApiKeyModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function ApiKeyModal({ isOpen, onClose }: ApiKeyModalProps) {
  const [provider, setProvider] = useState('OpenAI');
  const [name, setName] = useState('');
  const [key, setKey] = useState('');
  const [modelName, setModelName] = useState('');
  const [status, setStatus] = useState<{msg: string, type: 'success'|'error'} | null>(null);
  const [loading, setLoading] = useState(false);
  const [testStatuses, setTestStatuses] = useState<Record<string, 'testing' | 'success' | 'error'>>({});
  const [existingKeys, setExistingKeys] = useState<Record<string, Array<{name: string, key: string, model_name?: string}>>>({});

  useEffect(() => {
    if (isOpen) {
      fetchKeys();
    }
  }, [isOpen]);

  const fetchKeys = async () => {
    try {
      const keys = await api.getApiKeys();
      setExistingKeys(keys);
    } catch (e) {
      console.error('Failed to fetch keys', e);
    }
  };

  const handleSave = async () => {
    if (!name || !key) {
      setStatus({ msg: 'Name and Key are required', type: 'error' });
      return;
    }
    
    setLoading(true);
    setStatus(null);
    try {
      await api.addApiKey(provider, name, key, modelName);
      setStatus({ msg: 'Key saved persistently', type: 'success' });
      setName('');
      setKey('');
      setModelName('');
      fetchKeys();
      fetchKeys();
    } catch (e: any) {
      setStatus({ msg: e.response?.data?.detail || 'Failed to add key', type: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const handleTest = async (prov: string, keyName: string) => {
    const keyId = `${prov}-${keyName}`;
    setTestStatuses(prev => ({ ...prev, [keyId]: 'testing' }));
    
    try {
      const res = await api.testApiKey(prov, keyName);
      if (res.status === 'success') {
        setTestStatuses(prev => ({ ...prev, [keyId]: 'success' }));
      } else {
        setTestStatuses(prev => ({ ...prev, [keyId]: 'error' }));
      }
    } catch (e) {
      console.error('Failed to test key', e);
      setTestStatuses(prev => ({ ...prev, [keyId]: 'error' }));
      showNotification({
          type: 'error',
          title: 'Validation Failed',
          message: `The API key "${keyName}" for ${prov} failed validation. Please check your credentials.`
      });
    }
  };

  const { showNotification } = useNotification();

  const handleDelete = async (prov: string, keyName: string) => {
    showNotification({
      type: 'confirm',
      title: 'Delete API Key',
      message: `Are you sure you want to delete the API key "${keyName}" for ${prov}? Actions that require this key may fail.`,
      confirmText: 'Delete',
      onConfirm: async () => {
        try {
          await api.deleteApiKey(prov, keyName);
          showNotification({
            type: 'success',
            title: 'Key Deleted',
            message: `API key "${keyName}" has been removed.`
          });
          fetchKeys();
        } catch (e) {
          console.error('Failed to delete key', e);
          showNotification({
            type: 'error',
            title: 'Error',
            message: 'Failed to delete the API key. Please try again.'
          });
        }
      }
    });
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <motion.div 
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95 }}
        className="w-full max-w-2xl bg-[#0a0a0a] border border-white/10 rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]"
      >
        <div className="p-4 border-b border-white/10 flex justify-between items-center bg-white/5 shrink-0">
          <h2 className="font-semibold flex items-center gap-2 text-white">
            <Key className="w-4 h-4 text-primary" />
            API Keys
          </h2>
          <button onClick={onClose} className="p-1 hover:bg-white/10 rounded-lg transition-colors text-neutral-400">
            <X className="w-4 h-4" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          <div className="space-y-4">
            <h3 className="text-sm font-medium text-white/70">Add Persistent Key</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-xs font-medium text-neutral-400 uppercase">Provider</label>
                <select 
                  value={provider}
                  onChange={(e) => setProvider(e.target.value)}
                  className="w-full bg-black/50 border border-white/10 rounded-xl px-4 py-3 text-sm focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all text-white"
                >
                  {['OpenAI', 'Anthropic', 'Groq', 'Gemini', 'OpenRouter'].map(p => (
                    <option key={p} value={p}>{p}</option>
                  ))}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-medium text-neutral-400 uppercase">Key Name</label>
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="My Primary Key"
                  className="w-full bg-black/50 border border-white/10 rounded-xl px-4 py-3 text-sm focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all text-white"
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-medium text-neutral-400 uppercase">API Key</label>
                <input 
                  type="password" 
                  value={key}
                  onChange={(e) => setKey(e.target.value)}
                  placeholder="sk-..."
                  className="w-full bg-black/50 border border-white/10 rounded-xl px-4 py-3 text-sm focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all text-white"
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-medium text-neutral-400 uppercase">Model Name (Optional)</label>
                <input 
                  type="text" 
                  value={modelName}
                  onChange={(e) => setModelName(e.target.value)}
                  placeholder="gpt-4"
                  className="w-full bg-black/50 border border-white/10 rounded-xl px-4 py-3 text-sm focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all text-white"
                />
              </div>
            </div>
            {status && (
              <div className={cn(
                "text-sm p-3 rounded-lg border",
                status.type === 'success' ? "bg-green-500/10 border-green-500/20 text-green-400" : "bg-red-500/10 border-red-500/20 text-red-400"
              )}>
                {status.msg}
              </div>
            )}
            <button 
              onClick={handleSave}
              disabled={loading}
              className="w-full bg-primary hover:bg-primary-hover text-white py-3 rounded-xl font-medium transition-all flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Check className="w-4 h-4" />}
              Save Key
            </button>
          </div>

          <div className="space-y-4 pt-4 border-t border-white/10">
            <h3 className="text-sm font-medium text-white/70">Stored Keys</h3>
            <div className="grid gap-3">
              {Object.entries(existingKeys).flatMap(([prov, keys]) => 
                keys.map((k, i) => {
                  const keyId = `${prov}-${k.name}`;
                  const testStatus = testStatuses[keyId];
                  return (
                  <div key={`${prov}-${i}`} className={cn(
                    "flex items-center justify-between p-3 rounded-xl border transition-colors",
                    testStatus === 'success' ? "bg-green-500/10 border-green-500/30 shadow-[0_0_10px_rgba(34,197,94,0.1)]" : "bg-white/5 border-white/5"
                  )}>
                    <div className="flex items-center gap-3">
                      <div className={cn(
                        "w-8 h-8 rounded-lg flex items-center justify-center transition-colors",
                        testStatus === 'success' ? "bg-green-500/20 text-green-400" : "bg-white/5 text-neutral-400"
                      )}>
                        {testStatus === 'success' ? <CheckCircle className="w-4 h-4" /> : <Key className="w-4 h-4" />}
                      </div>
                      <div>
                        <div className="font-medium text-sm text-white flex items-center gap-2">
                          {k.name}
                          {testStatus === 'error' && <span className="text-[10px] bg-red-500/20 text-red-400 px-1.5 py-0.5 rounded font-bold tracking-wider">INVALID</span>}
                        </div>
                        <div className="text-xs text-neutral-500 uppercase">{prov} • {k.key}</div>
                      </div>
                    </div>
                    <div className="flex items-center gap-1">
                      <button 
                        onClick={() => handleTest(prov, k.name)} 
                        disabled={testStatus === 'testing'}
                        className={cn(
                          "p-2 rounded transition-colors flex items-center justify-center",
                          testStatus === 'testing' ? "text-primary opacity-50 cursor-not-allowed" : "text-neutral-500 hover:text-primary hover:bg-white/5"
                        )}
                        title="Test API Key"
                      >
                         {testStatus === 'testing' ? <Loader2 className="w-4 h-4 animate-spin" /> : <Zap className="w-4 h-4" />}
                      </button>
                      <button onClick={() => handleDelete(prov, k.name)} className="p-2 text-neutral-600 hover:text-red-400 hover:bg-red-500/10 rounded transition-colors" title="Delete API Key">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                )})
              )}
            </div>
          </div>
        </div>
      </motion.div>
    </div>
  );
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Send, Paperclip, Bot, User, Trash2, StopCircle, Zap, Settings2, Clock, ChevronDown, ChevronUp, Activity, X, Globe, FileText, BookOpen, Brain, MessageSquare, Database, Search, Mic, MicOff, Microscope, Scale, Star, AlertTriangle, Lightbulb, CheckCircle2, Loader2 } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import axios from 'axios';
import { api, Message, RetrievalConfig, QueryMetrics, JudgeEvaluation } from '@/lib/api';
import { cn } from '@/lib/utils';
import { motion, AnimatePresence } from 'framer-motion';
import { useNotification } from '@/context/NotificationContext';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { oneDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { Copy, Check } from 'lucide-react';
import DeepResearchPanel from './DeepResearchPanel';
import DiagramCard from './DiagramCard';

interface ChatInterfaceProps {
  chatId: string | null;
  onChatUpdated?: (chatId: string, updates: Partial<{ title: string }>) => void;
  onCreateSession?: () => Promise<string | null>;
}

const CodeBlock = ({ inline, className, children, ...props }: any) => {
  const match = /language-(\w+)/.exec(className || '');
  const [copied, setCopied] = useState(false);
  const { showNotification } = useNotification();

  const handleCopy = async () => {
    await navigator.clipboard.writeText(String(children).replace(/\n$/, ''));
    setCopied(true);
    showNotification({
      type: 'success',
      title: 'Copied',
      message: 'Code copied to clipboard'
    });
    setTimeout(() => setCopied(false), 2000);
  };

  if (!inline && match && match[1]?.toLowerCase() === 'mermaid') {
    return <DiagramCard mermaidCode={String(children || '')} />;
  }

  return !inline && match ? (
    <div className="relative group rounded-xl overflow-hidden my-4 border border-white/10 bg-[#1e1e1e]">
      <div className="flex items-center justify-between px-4 py-2 bg-white/5 border-b border-white/5">
        <span className="text-xs text-neutral-400 font-mono">{match[1]}</span>
        <button
          onClick={handleCopy}
          className="flex items-center gap-1.5 text-xs text-neutral-400 hover:text-white transition-colors"
        >
          {copied ? <Check className="w-3.5 h-3.5" /> : <Copy className="w-3.5 h-3.5" />}
          {copied ? 'Copied!' : 'Copy'}
        </button>
      </div>
      <SyntaxHighlighter
        style={oneDark}
        language={match[1]}
        PreTag="div"
        customStyle={{
          margin: 0,
          background: 'transparent',
          padding: '1.5rem',
          fontSize: '0.875rem',
          lineHeight: '1.5'
        }}
        {...props}
      >
        {String(children).replace(/\n$/, '')}
      </SyntaxHighlighter>
    </div>
  ) : (
    <code className={cn("bg-white/10 text-primary px-1.5 py-0.5 rounded text-sm font-mono", className)} {...props}>
      {children}
    </code>
  );
};

export function ChatInterface({ chatId, onChatUpdated, onCreateSession }: ChatInterfaceProps) {
  const { showNotification } = useNotification();
  const [input, setInput] = useState('');
  const [history, setHistory] = useState<Message[]>([]);
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  
  // Retrieval mode state
  const [retrievalMode, setRetrievalMode] = useState<'fast' | 'advanced'>('advanced');
  const [showAdvancedOptions, setShowAdvancedOptions] = useState(false);
  const [algorithms, setAlgorithms] = useState({
    use_vector: true,
    use_graph: true,
    use_pagerank: true,
    use_bm25: true,
    use_structural: true,
    use_mmr: true
  });
  const [lastMetrics, setLastMetrics] = useState<QueryMetrics | null>(null);
  const [showMetricsOverlay, setShowMetricsOverlay] = useState(false);

  // Memory viewer state
  const [showMemoryViewer, setShowMemoryViewer] = useState(false);
  const [memoryDump, setMemoryDump] = useState<any>(null);
  const [memoryLoading, setMemoryLoading] = useState(false);
  const [memoryTab, setMemoryTab] = useState<'conversation' | 'fragments' | 'web' | 'traces'>('conversation');

  // LLM Judge state
  const [showJudgeViewer, setShowJudgeViewer] = useState(false);
  const [judgeEvaluations, setJudgeEvaluations] = useState<JudgeEvaluation[]>([]);
  const [judgeLoading, setJudgeLoading] = useState(false);
  const [evaluatingIndex, setEvaluatingIndex] = useState<number | null>(null);
  const [selectedEvaluation, setSelectedEvaluation] = useState<JudgeEvaluation | null>(null);

  // Search mode: web_search (with fallback), knowledge_base (local only), or deep_research
  const [searchMode, setSearchMode] = useState<'web_search' | 'knowledge_base' | 'deep_research'>('knowledge_base');

  // Deep Research state
  const [deepResearchSessionId, setDeepResearchSessionId] = useState<string | null>(null);
  const [isDeepResearching, setIsDeepResearching] = useState(false);

  const API_BASE = process.env.NEXT_PUBLIC_API_URL || 'http://127.0.0.1:8010';

  // Abort controller for stopping queries
  const abortControllerRef = useRef<AbortController | null>(null);

  // Speech recognition state
  const [isListening, setIsListening] = useState(false);
  const [interimText, setInterimText] = useState('');
  const [recordingTime, setRecordingTime] = useState(0);
  const [speechSupported, setSpeechSupported] = useState(false);
  const recognitionRef = useRef<any>(null);
  const recordingTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Initialize speech recognition
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setSpeechSupported(false);
      return;
    }
    setSpeechSupported(true);

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'en-US';
    recognition.maxAlternatives = 1;

    recognition.onresult = (event: any) => {
      let finalTranscript = '';
      let interimTranscript = '';

      for (let i = event.resultIndex; i < event.results.length; i++) {
        const transcript = event.results[i][0].transcript;
        if (event.results[i].isFinal) {
          finalTranscript += transcript;
        } else {
          interimTranscript += transcript;
        }
      }

      if (finalTranscript) {
        setInput(prev => {
          const spacer = prev && !prev.endsWith(' ') ? ' ' : '';
          return prev + spacer + finalTranscript.trim();
        });
        setInterimText('');
      } else {
        setInterimText(interimTranscript);
      }
    };

    recognition.onerror = (event: any) => {
      console.error('Speech recognition error:', event.error);
      if (event.error !== 'no-speech') {
        setIsListening(false);
        setInterimText('');
      }
    };

    recognition.onend = () => {
      // If we're still supposed to be listening, restart (handles auto-stop)
      if (recognitionRef.current?._shouldRestart) {
        try {
          recognition.start();
        } catch (e) {
          setIsListening(false);
        }
      } else {
        setIsListening(false);
        setInterimText('');
      }
    };

    recognitionRef.current = recognition;

    return () => {
      recognition.abort();
      if (recordingTimerRef.current) clearInterval(recordingTimerRef.current);
    };
  }, []);

  const toggleListening = useCallback(() => {
    const recognition = recognitionRef.current;
    if (!recognition) return;

    if (isListening) {
      // Stop listening
      recognition._shouldRestart = false;
      recognition.stop();
      setIsListening(false);
      setInterimText('');
      setRecordingTime(0);
      if (recordingTimerRef.current) {
        clearInterval(recordingTimerRef.current);
        recordingTimerRef.current = null;
      }
    } else {
      // Start listening
      try {
        recognition._shouldRestart = true;
        recognition.start();
        setIsListening(true);
        setRecordingTime(0);
        recordingTimerRef.current = setInterval(() => {
          setRecordingTime(prev => prev + 1);
        }, 1000);
      } catch (e) {
        console.error('Failed to start speech recognition:', e);
      }
    }
  }, [isListening]);

  useEffect(() => {
    const loadHistory = async () => {
      if (!chatId) {
          setHistory([]);
          return;
      }
      try {
        setLoading(true);
        const savedHistory = await api.getChatHistory(chatId);
        setHistory(savedHistory || []);
      } catch (err) {
        console.error('Failed to load history:', err);
      } finally {
        setLoading(false);
      }
    };
    loadHistory();
  }, [chatId]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, loading]);


  const handleSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || loading) return;

    // Stop speech recognition if active
    if (isListening) {
      const recognition = recognitionRef.current;
      if (recognition) {
        recognition._shouldRestart = false;
        recognition.stop();
      }
      setIsListening(false);
      setInterimText('');
      setRecordingTime(0);
      if (recordingTimerRef.current) {
        clearInterval(recordingTimerRef.current);
        recordingTimerRef.current = null;
      }
    }

    const userMsg: Message = { role: 'user', content: input };
    setHistory(prev => [...prev, userMsg]);
    const queryText = input;
    setInput('');
    setLoading(true);

    // If no chat ID (New Chat state), create a session first
    let activeChatId = chatId;
    if (!activeChatId) {
      if (onCreateSession) {
        try {
          const newId = await onCreateSession();
          if (newId) {
            activeChatId = newId;
          } else {
             throw new Error("Failed to create new chat session");
          }
        } catch (e) {
          console.error("Auto-creation failed", e);
          setLoading(false);
          return;
        }
      } else {
        // No create handler, cannot proceed
        setLoading(false);
        return;
      }
    }

    // ─── Deep Research Mode ───
    if (searchMode === 'deep_research') {
      try {
        const res = await api.startResearch(queryText, activeChatId!);
        setDeepResearchSessionId(res.session_id);
        setIsDeepResearching(true);
        setLoading(false);

        if (onChatUpdated && activeChatId) {
          const researchTitle = `🔬 ${queryText.slice(0, 40)}...`;
          onChatUpdated(activeChatId, { title: researchTitle });
          try { await api.renameChat(activeChatId, researchTitle); } catch {}
        }
        return;
      } catch (err) {
        console.error('Failed to start deep research:', err);
        showNotification({
          type: 'error',
          title: 'Research Failed',
          message: 'Could not start deep research. Check backend status.'
        });
        setLoading(false);
        return;
      }
    }
    
    // ─── Normal Query Mode ───
    const controller = new AbortController();
    abortControllerRef.current = controller;

    try {
      // Build config for API with search mode
      const config: RetrievalConfig = {
        mode: retrievalMode,
        ...(retrievalMode === 'advanced' ? algorithms : {}),
        search_mode: searchMode
      };

      const response = await api.query(userMsg.content, activeChatId!, history, config, controller.signal);
      
      const assistantMsg: Message = { 
        role: 'assistant', 
        content: response.answer || "Sorry, I couldn't generate a response.",
        sources: response.sources,
        metrics: response.metrics
      };
      
      if (response.metrics) {
        setLastMetrics(response.metrics);
      }

      if (response.chat_title && activeChatId && onChatUpdated) {
        onChatUpdated(activeChatId, { title: response.chat_title });
      }
      
      setHistory(prev => [...prev, assistantMsg]);
    } catch (err) {
      // Check if this was an intentional abort (stop button)
      if (axios.isCancel(err) || (err instanceof DOMException && err.name === 'AbortError')) {
        // User clicked stop - append stopped message
        const stoppedMsg: Message = { role: 'assistant', content: '⏹ Generation stopped by user.' };
        setHistory(prev => [...prev, stoppedMsg]);
      } else {
        console.error('Query error', err);
        showNotification({
          type: 'error',
          title: 'Query Failed',
          message: 'There was an issue connecting to the Albot engine. please check the backend status.'
        });
        const errorMsg: Message = { role: 'assistant', content: `**Error**: ${err instanceof Error ? err.message : 'Unknown error'}` };
        setHistory(prev => [...prev, errorMsg]);
      }
    } finally {
      setLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStop = async () => {
    // Abort the in-flight HTTP request
    abortControllerRef.current?.abort();

    // Also notify the backend to cancel server-side processing
    // Also notify the backend to cancel server-side processing
    if (chatId) {
      try {
        await api.cancelQuery(chatId);
      } catch (e) {
        // Best-effort — the abort above is the primary mechanism
        console.warn('Backend cancel failed:', e);
      }
    }
  };

  const clearChat = () => {
    if (!chatId) return;
    
    showNotification({
      type: 'confirm',
      title: 'Clear Conversation',
      message: 'Are you sure you want to clear the entire chat history? This cannot be undone.',
      confirmText: 'Clear',
      onConfirm: async () => {
        try {
          await api.clearChatHistory(chatId);
          setHistory([]);
          showNotification({
            type: 'success',
            title: 'History Cleared',
            message: 'Conversation history has been reset.'
          });
        } catch (err) {
           console.error('Failed to clear history:', err);
           showNotification({
            type: 'error',
            title: 'Error',
            message: 'Failed to clear history on backend.'
          });
        }
      }
    });
  };

  const handleDeleteMemoryItem = async (type: 'conversation' | 'fragments' | 'web' | 'traces', id: string | number) => {
    showNotification({
      type: 'confirm',
      title: 'Delete Memory Item',
      message: 'Are you sure you want to delete this memory item? This action cannot be undone.',
      confirmText: 'Delete',
      onConfirm: async () => {
        try {
          if (type === 'conversation') {
            await api.deleteMessage(id as number);
            setMemoryDump((prev: any) => prev ? ({
              ...prev,
              conversation_log: prev.conversation_log.filter((m: any) => m.id !== id),
              stats: { ...prev.stats, total_messages: prev.stats.total_messages - 1 }
            }) : null);
          } else if (type === 'fragments') {
            await api.deleteMemoryFragment(id as string);
            setMemoryDump((prev: any) => prev ? ({
              ...prev,
              fragments: prev.fragments.filter((f: any) => f.fragment_id !== id),
              stats: { ...prev.stats, total_fragments: prev.stats.total_fragments - 1 }
            }) : null);
          } else if (type === 'web') {
            await api.deleteWebLog(id as number);
            setMemoryDump((prev: any) => prev ? ({
              ...prev,
              web_history: prev.web_history.filter((w: any) => w.id !== id),
              stats: { ...prev.stats, total_web_searches: prev.stats.total_web_searches - 1 }
            }) : null);
          } else if (type === 'traces') {
            await api.deleteTrace(id as string);
            setMemoryDump((prev: any) => prev ? ({
              ...prev,
              reasoning_traces: prev.reasoning_traces.filter((t: any) => t.id !== id),
              stats: { ...prev.stats, total_traces: prev.stats.total_traces - 1 }
            }) : null);
          }
          showNotification({
            type: 'success',
            title: 'Deleted',
            message: 'Memory item deleted successfully.'
          });
        } catch (err) {
          console.error('Failed to delete memory item:', err);
          showNotification({
            type: 'error',
            title: 'Error',
            message: 'Failed to delete memory item.'
          });
        }
      }
    });
  };



  return (
    <div className="flex-1 flex flex-col h-full relative">
      <div className="absolute top-4 right-8 z-20 flex gap-2">
        {history.some(m => m.metrics) && (
          <button 
            type="button" 
            onClick={() => setShowMetricsOverlay(true)}
            className="px-3 py-1.5 bg-white/5 hover:bg-primary/10 text-neutral-400 hover:text-primary rounded-lg transition-all border border-white/5 text-[10px] uppercase tracking-widest font-bold flex items-center gap-2 group/btn backdrop-blur-md"
          >
            <Activity className="w-3.5 h-3.5" />
          </button>
        )}
        {chatId && history.some(m => m.role === 'assistant') && (
          <button 
            type="button" 
            onClick={async () => {
              setShowJudgeViewer(true);
              setJudgeLoading(true);
              try {
                const res = await api.getEvaluations(chatId);
                setJudgeEvaluations(res.evaluations || []);
                if (res.evaluations?.length > 0) {
                  setSelectedEvaluation(res.evaluations[res.evaluations.length - 1]);
                }
              } catch (err) {
                console.error('Failed to load judge evaluations:', err);
              } finally {
                setJudgeLoading(false);
              }
            }}
            className="px-3 py-1.5 bg-white/5 hover:bg-amber-500/10 text-neutral-400 hover:text-amber-400 rounded-lg transition-all border border-white/5 text-[10px] uppercase tracking-widest font-bold flex items-center gap-2 group/btn backdrop-blur-md"
          >
            <Scale className="w-3.5 h-3.5" />
            Judge
          </button>
        )}
        {chatId && (
          <button 
            type="button" 
            onClick={async () => {
              setShowMemoryViewer(true);
              setMemoryLoading(true);
              try {
                const dump = await api.getMemoryDump(chatId);
                setMemoryDump(dump);
              } catch (err) {
                console.error('Failed to load memory dump:', err);
              } finally {
                setMemoryLoading(false);
              }
            }}
            className="px-3 py-1.5 bg-white/5 hover:bg-purple-500/10 text-neutral-400 hover:text-purple-400 rounded-lg transition-all border border-white/5 text-[10px] uppercase tracking-widest font-bold flex items-center gap-2 group/btn backdrop-blur-md"
          >
            <Brain className="w-3.5 h-3.5" />
            Memory
          </button>
        )}
        {history.length > 0 && (
          <button 
            type="button" 
            onClick={clearChat}
            className="px-3 py-1.5 bg-white/5 hover:bg-red-500/10 text-neutral-400 hover:text-red-400 rounded-lg transition-all border border-white/5 text-[10px] uppercase tracking-widest font-bold flex items-center gap-2 group/btn backdrop-blur-md"
          >
            <Trash2 className="w-3.5 h-3.5" />
            Clear Chat
          </button>
        )}
      </div>

      <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6" ref={scrollRef}>
        {history.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-neutral-500 space-y-4">
             <div className="w-24 h-24 rounded-2xl bg-white/5 flex items-center justify-center shadow-[0_0_30px_rgba(147,51,234,0.1)]">
                <Bot className="w-12 h-12 text-primary/50" />
             </div>
             <p className="text-lg font-medium">Hello! I'm Albot. How can I assist you today?</p>
          </div>
        )}
        
        <AnimatePresence mode="popLayout">
          {history.map((msg, idx) => (
            <motion.div 
              key={idx} 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
            >
              <div className={cn(
                "w-8 h-8 rounded-lg flex items-center justify-center shrink-0 mt-1",
                msg.role === 'user' ? "bg-primary/20 border border-primary/30" : "bg-white/5 border border-white/10"
              )}>
                {msg.role === 'user' ? <User className="w-4 h-4 text-primary" /> : <Bot className="w-4 h-4 text-primary" />}
              </div>
              <div className={`
                max-w-[92%] rounded-2xl px-5 py-4 text-[15px] leading-relaxed shadow-lg transition-all
                ${msg.role === 'user' 
                  ? 'bg-primary text-white rounded-tr-none' 
                  : 'bg-white/5 border border-white/10 text-neutral-200 rounded-tl-none'}
              `}>
                {msg.role === 'assistant' ? (
                  <div className="flex flex-col gap-3">
                    <div className="prose prose-invert prose-base max-w-none prose-p:leading-relaxed prose-pre:my-4 prose-p:my-3 prose-headings:mb-4 prose-headings:mt-6 first:prose-headings:mt-0">
                      <ReactMarkdown
                        remarkPlugins={[remarkGfm]}
                        components={{
                          code: CodeBlock,
                          table: ({ children }) => (
                            <div className="overflow-x-auto my-4 border border-white/10 rounded-xl">
                              <table className="w-full text-left text-sm border-collapse">
                                {children}
                              </table>
                            </div>
                          ),
                          thead: ({ children }) => (
                            <thead className="bg-white/5 text-neutral-200 border-b border-white/10">
                              {children}
                            </thead>
                          ),
                          tbody: ({ children }) => (
                            <tbody className="divide-y divide-white/5">
                              {children}
                            </tbody>
                          ),
                          tr: ({ children }) => (
                            <tr className="hover:bg-white/5 transition-colors">
                              {children}
                            </tr>
                          ),
                          th: ({ children }) => (
                            <th className="px-4 py-3 font-medium text-xs uppercase tracking-wider">
                              {children}
                            </th>
                          ),
                          td: ({ children }) => (
                            <td className="px-4 py-3 text-neutral-400">
                              {children}
                            </td>
                          ),
                          blockquote: ({ children }) => (
                            <blockquote className="border-l-4 border-primary/40 pl-4 py-1 my-4 italic text-neutral-400 bg-primary/5 rounded-r-lg">
                              {children}
                            </blockquote>
                          ),
                          ul: ({ children }) => (
                            <ul className="list-disc list-outside ml-4 space-y-1 my-2 text-neutral-300">
                              {children}
                            </ul>
                          ),
                          ol: ({ children }) => (
                            <ol className="list-decimal list-outside ml-4 space-y-1 my-2 text-neutral-300">
                              {children}
                            </ol>
                          )
                        }}
                      >
                        {msg.content}
                      </ReactMarkdown>
                      <div className="mt-4 flex justify-end">
                         <button
                          onClick={() => {
                            navigator.clipboard.writeText(msg.content);
                            showNotification({
                              type: 'success',
                              title: 'Copied',
                              message: 'Response copied to clipboard'
                            });
                          }}
                          className="flex items-center gap-1.5 text-[10px] text-neutral-500 hover:text-neutral-300 transition-colors uppercase tracking-widest font-bold px-2 py-1 rounded hover:bg-white/5"
                        >
                          <Copy className="w-3 h-3" />
                          Copy Response
                        </button>
                      </div>
                    </div>
                    {msg.sources && msg.sources.length > 0 && (
                      <div className="pt-3 border-t border-white/10 mt-1">
                        <p className="text-[10px] uppercase tracking-wider font-bold text-neutral-500 mb-2">Sources</p>
                        <div className="flex flex-wrap gap-2">
                          {msg.sources.map((src, i) => {
                            const isUrl = src.startsWith('http');
                            let displayName = src;
                            if (isUrl) {
                              try {
                                const url = new URL(src);
                                displayName = url.hostname.replace('www.', '');
                              } catch (e) {
                                displayName = 'Link';
                              }
                            }
                            return (
                              <a 
                                key={i} 
                                href={isUrl ? src : undefined}
                                target="_blank"
                                rel="noopener noreferrer"
                                className={cn(
                                  "px-2 py-0.5 rounded-full bg-white/5 border border-white/10 text-[10px] text-neutral-400 flex items-center gap-1 transition-colors",
                                  isUrl ? "hover:bg-primary/10 hover:border-primary/30 hover:text-primary pointer-events-auto" : "pointer-events-none"
                                )}
                              >
                                {isUrl ? <Globe className="w-2.5 h-2.5" /> : <FileText className="w-2.5 h-2.5" />}
                                {displayName}
                              </a>
                            );
                          })}
                        </div>
                      </div>
                    )}
                    {msg.metrics && (
                      <div className="pt-2 flex justify-end gap-2">
                        <button 
                          onClick={() => {
                            setLastMetrics(msg.metrics || null);
                            setShowMetricsOverlay(true);
                          }}
                          className="text-[9px] uppercase tracking-widest font-bold text-primary hover:bg-primary/10 transition-colors flex items-center gap-1 bg-primary/5 px-2 py-1 rounded-lg border border-primary/10"
                        >
                          <Zap className="w-2.5 h-2.5" />
                          Technical Report
                        </button>
                        {chatId && (
                          <button
                            disabled={evaluatingIndex === idx}
                            onClick={async () => {
                              // Find the preceding user message
                              const userMsgs = history.slice(0, idx).filter(m => m.role === 'user');
                              const lastUserMsg = userMsgs[userMsgs.length - 1];
                              if (!lastUserMsg || !chatId) return;
                              setEvaluatingIndex(idx);
                              try {
                                const res = await api.evaluateResponse(
                                  chatId,
                                  idx,
                                  lastUserMsg.content,
                                  msg.content,
                                  msg.sources
                                );
                                showNotification({
                                  type: 'success',
                                  title: 'Evaluated',
                                  message: `Verdict: ${res.evaluation.verdict} (${res.evaluation.overall_score}/10)`
                                });
                                // Update local evaluations cache
                                setJudgeEvaluations(prev => [...prev, { ...res.evaluation, id: res.id, message_index: idx }]);
                              } catch (err) {
                                console.error('Judge evaluation failed:', err);
                                showNotification({
                                  type: 'error',
                                  title: 'Evaluation Failed',
                                  message: 'Could not evaluate this response.'
                                });
                              } finally {
                                setEvaluatingIndex(null);
                              }
                            }}
                            className="text-[9px] uppercase tracking-widest font-bold text-amber-400 hover:bg-amber-500/10 transition-colors flex items-center gap-1 bg-amber-500/5 px-2 py-1 rounded-lg border border-amber-500/10 disabled:opacity-50"
                          >
                            {evaluatingIndex === idx ? (
                              <Loader2 className="w-2.5 h-2.5 animate-spin" />
                            ) : (
                              <Scale className="w-2.5 h-2.5" />
                            )}
                            {evaluatingIndex === idx ? 'Judging...' : 'Evaluate'}
                          </button>
                        )}
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="prose prose-invert max-w-none prose-p:text-neutral-300 prose-headings:text-neutral-200 prose-strong:text-white prose-a:text-primary prose-a:no-underline hover:prose-a:underline prose-code:text-primary prose-code:bg-white/5 prose-code:px-1 prose-code:rounded prose-pre:bg-transparent prose-pre:p-0">
                    <ReactMarkdown>{msg.content}</ReactMarkdown>
                  </div>
                )}
              </div>
            </motion.div>
          ))}
          
          {loading && !isDeepResearching && (
             <motion.div 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="flex gap-3 justify-start"
            >
               <div className="w-8 h-8 rounded-lg bg-white/5 border border-white/10 flex items-center justify-center shrink-0 mt-1">
                 <Bot className="w-4 h-4 text-primary animate-pulse" />
               </div>
               <div className="bg-white/5 border border-white/10 rounded-2xl px-5 py-4 rounded-tl-none flex flex-col gap-2 min-w-[200px]">
                 <div className="flex gap-1.5">
                   <span className="w-1.5 h-1.5 rounded-full bg-primary animate-bounce shadow-[0_0_8px_rgba(147,51,234,0.5)]" style={{ animationDelay: '0s' }}></span>
                   <span className="w-1.5 h-1.5 rounded-full bg-primary animate-bounce shadow-[0_0_8px_rgba(147,51,234,0.5)]" style={{ animationDelay: '0.2s' }}></span>
                   <span className="w-1.5 h-1.5 rounded-full bg-primary animate-bounce shadow-[0_0_8px_rgba(147,51,234,0.5)]" style={{ animationDelay: '0.4s' }}></span>
                 </div>
                 <p className="text-[10px] uppercase tracking-[0.2em] font-black text-neutral-500 animate-pulse">
                    Thinking & Retrieving Evidence...
                 </p>
               </div>
            </motion.div>
          )}

          {/* Deep Research Panel */}
          {isDeepResearching && deepResearchSessionId && (
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
            >
              <DeepResearchPanel
                sessionId={deepResearchSessionId}
                query={history.filter(m => m.role === 'user').pop()?.content || ''}
                apiBaseUrl={API_BASE}
                onComplete={(report: string, sources: string[], metrics?: any) => {
                  // Avoid duplication if the message with this content already exists
                  setHistory(prev => {
                    const exists = prev.some(m => m.role === 'assistant' && m.content === report);
                    if (exists) return prev;
                    
                    const researchMsg: Message = {
                      role: 'assistant',
                      content: report,
                      sources: sources,
                      metrics: metrics || { type: 'deep_research' } 
                    };
                    return [...prev, researchMsg];
                  });
                  if (metrics) {
                    setLastMetrics(metrics);
                  }
                  setIsDeepResearching(false);
                  setDeepResearchSessionId(null);
                }}
                onCancel={() => {
                  setIsDeepResearching(false);
                  setDeepResearchSessionId(null);
                }}
              />
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      <div className="p-4 md:p-6 w-full max-w-4xl mx-auto space-y-4">
        {/* Search Mode & RAG Mode Panel */}
        <div className="flex flex-col gap-3">
          <div className="flex items-center justify-between px-2 flex-wrap gap-2">
            <div className="flex items-center gap-3">
              {/* Search Mode Toggle */}
              <div className="flex bg-white/5 p-1 rounded-xl border border-white/10">
                <button
                  onClick={() => setSearchMode('knowledge_base')}
                  className={cn(
                    "flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium transition-all",
                    searchMode === 'knowledge_base' 
                      ? "bg-purple-600 text-white shadow-lg shadow-purple-600/20" 
                      : "text-neutral-400 hover:text-neutral-200"
                  )}
                >
                  <BookOpen className="w-3.5 h-3.5" />
                  Knowledge Base
                </button>
                <button
                  onClick={() => setSearchMode('web_search')}
                  className={cn(
                    "flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium transition-all",
                    searchMode === 'web_search' 
                      ? "bg-purple-600 text-white shadow-lg shadow-purple-600/20" 
                      : "text-neutral-400 hover:text-neutral-200"
                  )}
                >
                  <Globe className="w-3.5 h-3.5" />
                  Web Search
                </button>
                <button
                  onClick={() => setSearchMode('deep_research')}
                  className={cn(
                    "flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium transition-all",
                    searchMode === 'deep_research' 
                      ? "bg-purple-600 text-white shadow-lg shadow-purple-600/20" 
                      : "text-neutral-400 hover:text-neutral-200"
                  )}
                >
                  <Microscope className="w-3.5 h-3.5" />
                  Deep Research
                </button>
              </div>

              {/* Retrieval Mode Toggle */}
              <div className="flex bg-white/5 p-1 rounded-xl border border-white/10">
                <button
                  onClick={() => setRetrievalMode('fast')}
                  className={cn(
                    "flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium transition-all",
                    retrievalMode === 'fast' 
                      ? "bg-primary text-white shadow-lg shadow-primary/20" 
                      : "text-neutral-400 hover:text-neutral-200"
                  )}
                >
                  <Zap className="w-3.5 h-3.5" />
                  Fast RAG
                </button>
                <button
                  onClick={() => setRetrievalMode('advanced')}
                  className={cn(
                    "flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium transition-all",
                    retrievalMode === 'advanced' 
                      ? "bg-primary text-white shadow-lg shadow-primary/20" 
                      : "text-neutral-400 hover:text-neutral-200"
                  )}
                >
                  <Settings2 className="w-3.5 h-3.5" />
                  Advanced RAG
                </button>
              </div>
            </div>

            {retrievalMode === 'advanced' && (
              <button
                type="button"
                onClick={() => setShowAdvancedOptions(!showAdvancedOptions)}
                className={cn(
                  "flex items-center gap-2 px-3 py-1.5 rounded-lg text-[10px] uppercase tracking-widest font-black transition-all border",
                  showAdvancedOptions 
                    ? "bg-primary/20 border-primary/30 text-primary" 
                    : "bg-white/5 border-white/10 text-neutral-500 hover:text-neutral-300 shadow-lg"
                )}
              >
                <Settings2 className="w-3 h-3" />
                {showAdvancedOptions ? "Hide Algos" : "Configure Algos"}
                {showAdvancedOptions ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
              </button>
            )}
          </div>

          {retrievalMode === 'advanced' && (
            <AnimatePresence>
              {showAdvancedOptions && (
                <motion.div 
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: 'auto' }}
                  exit={{ opacity: 0, height: 0 }}
                  className="overflow-hidden mt-2"
                >
                  <div className="bg-white/5 rounded-2xl border border-white/10 p-4 grid grid-cols-2 lg:grid-cols-6 gap-4">
                    {Object.entries(algorithms).map(([key, enabled]) => (
                      <div 
                        key={key} 
                        onClick={() => setAlgorithms(prev => ({ ...prev, [key]: !enabled }))}
                        className="flex items-center gap-2 cursor-pointer group select-none"
                      >
                        <div 
                          className={cn(
                            "w-4 h-4 rounded border flex items-center justify-center transition-all duration-200",
                            enabled 
                              ? "bg-primary border-primary shadow-[0_0_8px_rgba(147,51,234,0.4)]" 
                              : "border-white/20 group-hover:border-white/40"
                          )}
                        >
                          {enabled && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
                        </div>
                        <span className={cn(
                          "text-[10px] uppercase tracking-wider font-bold transition-colors",
                          enabled ? "text-neutral-200" : "text-neutral-500 group-hover:text-neutral-400"
                        )}>
                          {key.replace('use_', '').replace('_', ' ')}
                        </span>
                      </div>
                    ))}
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          )}
        </div>

        <form onSubmit={handleSubmit} className="relative group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={isListening ? 'Listening...' : `Ask Albot anything... (${searchMode === 'deep_research' ? '🔬 Deep Research' : searchMode === 'knowledge_base' ? '📚 KB' : '🌐 Web'} · ${retrievalMode} RAG)`}
            className={cn(
              "w-full input-glass rounded-2xl py-4 pl-5 text-sm focus:outline-none transition-all placeholder:text-neutral-500 text-white shadow-2xl",
              isListening ? "pr-28 border-red-500/30 shadow-[0_0_20px_rgba(239,68,68,0.1)]" : "pr-24"
            )}
            disabled={loading}
          />
          <div className="absolute right-2 top-2 flex items-center gap-1">
            {/* Mic Button */}
            {speechSupported && !loading && (
              <button 
                type="button"
                onClick={toggleListening}
                className={cn(
                  "p-2 rounded-xl transition-all duration-300 active:scale-95 relative",
                  isListening 
                    ? "bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/40 shadow-[0_0_15px_rgba(239,68,68,0.2)]" 
                    : "bg-white/10 hover:bg-white/20 text-neutral-400 hover:text-white"
                )}
                title={isListening ? 'Stop recording' : 'Voice input'}
              >
                {isListening ? (
                  <>
                    <MicOff className="w-5 h-5" />
                    {/* Pulse rings */}
                    <span className="absolute inset-0 rounded-xl border-2 border-red-500/50 animate-ping" />
                    <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.8)]" />
                  </>
                ) : (
                  <Mic className="w-5 h-5" />
                )}
              </button>
            )}
            {/* Send / Stop Button */}
            {loading ? (
              <button 
                type="button"
                onClick={handleStop}
                className="p-2 bg-red-500/20 hover:bg-red-500/40 text-red-400 hover:text-red-300 rounded-xl transition-colors active:scale-95 duration-200 border border-red-500/30"
                title="Stop generation"
              >
                <StopCircle className="w-5 h-5" />
              </button>
            ) : (
              <button 
                type="submit"
                disabled={!input.trim()}
                className="p-2 bg-white/10 hover:bg-primary text-white rounded-xl transition-colors disabled:opacity-50 disabled:hover:bg-white/10 group-hover:scale-105 active:scale-95 duration-200"
              >
                <Send className="w-5 h-5" />
              </button>
            )}
          </div>
        </form>

        {/* Voice Recording Indicator */}
        <AnimatePresence>
          {isListening && (
            <motion.div
              initial={{ opacity: 0, y: -8, height: 0 }}
              animate={{ opacity: 1, y: 0, height: 'auto' }}
              exit={{ opacity: 0, y: -8, height: 0 }}
              className="overflow-hidden"
            >
              <div className="flex items-center gap-3 px-4 py-2.5 bg-red-500/10 border border-red-500/20 rounded-xl mt-2">
                {/* Animated waveform bars */}
                <div className="flex items-center gap-0.5 h-4">
                  {[0, 1, 2, 3, 4].map(i => (
                    <div
                      key={i}
                      className="w-1 bg-red-400 rounded-full"
                      style={{
                        animation: `speechWave 0.8s ease-in-out ${i * 0.12}s infinite alternate`,
                        height: '4px',
                      }}
                    />
                  ))}
                </div>
                <span className="text-[10px] uppercase tracking-widest font-black text-red-400">
                  Recording
                </span>
                <span className="text-[10px] font-mono text-red-400/60">
                  {Math.floor(recordingTime / 60)}:{String(recordingTime % 60).padStart(2, '0')}
                </span>
                {interimText && (
                  <span className="text-xs text-neutral-400 italic truncate flex-1 ml-2">
                    {interimText}
                  </span>
                )}
                <button
                  type="button"
                  onClick={toggleListening}
                  className="text-[9px] uppercase tracking-widest font-black text-red-400 hover:text-red-300 transition-colors px-2 py-1 bg-red-500/10 rounded-lg border border-red-500/20 hover:border-red-500/30 ml-auto"
                >
                  Stop
                </button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
        <p className="text-center text-[10px] text-neutral-600 uppercase tracking-widest font-medium">
           Albot Multi-Modal Intelligence Engine v1.0
        </p>
      </div>

      {/* Analytics Overlay */}
      <AnimatePresence>
        {showMetricsOverlay && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 backdrop-blur-xl bg-black/40"
          >
            <motion.div 
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="w-full max-w-5xl bg-[#0a0a0a] border border-white/10 rounded-3xl overflow-hidden shadow-[0_0_100px_rgba(147,51,234,0.15)] flex flex-col max-h-[90vh]"
            >
              <div className="p-6 border-b border-white/5 flex justify-between items-center bg-white/5">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-primary/20 flex items-center justify-center border border-primary/30">
                    <Activity className="w-5 h-5 text-primary" />
                  </div>
                  <div>
                    <h2 className="text-lg font-bold text-white tracking-tight uppercase">Technical Intelligence Report</h2>
                    <p className="text-[10px] text-neutral-500 uppercase tracking-widest font-bold">Deep Retrieval Analytics</p>
                  </div>
                </div>
                <button 
                  onClick={() => setShowMetricsOverlay(false)}
                  className="p-2 hover:bg-white/5 rounded-xl transition-colors text-neutral-400"
                >
                  <X className="w-6 h-6" />
                </button>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-8">
                 {lastMetrics ? (
                   <section className="space-y-4">
                      <div className="flex items-center gap-2 px-1">
                        <Zap className="w-4 h-4 text-primary" />
                        <h3 className="text-xs font-black uppercase tracking-[0.2em] text-neutral-400">Current Turn Analysis</h3>
                      </div>
                       {lastMetrics.type === 'deep_research' ? (
                         <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="bg-purple-600/10 p-5 rounded-2xl border border-purple-500/20 flex flex-col gap-1 shadow-lg shadow-purple-500/5">
                              <span className="text-[10px] uppercase tracking-widest text-purple-400 font-black">Total Research Time</span>
                              <span className="text-2xl font-black tracking-tighter text-white">
                                {(lastMetrics.total_time_ms / 1000).toFixed(1)}<span className="text-sm ml-1 opacity-50 uppercase">sec</span>
                              </span>
                            </div>
                            <div className="bg-blue-600/10 p-5 rounded-2xl border border-blue-500/20 flex flex-col gap-1 shadow-lg shadow-blue-500/5">
                              <span className="text-[10px] uppercase tracking-widest text-blue-400 font-black">Sources Discovered</span>
                              <span className="text-2xl font-black tracking-tighter text-white">
                                {lastMetrics.total_sources || 0}<span className="text-sm ml-1 opacity-50 uppercase">links</span>
                              </span>
                            </div>
                            <div className="bg-emerald-600/10 p-5 rounded-2xl border border-emerald-500/20 flex flex-col gap-1 shadow-lg shadow-emerald-500/5">
                              <span className="text-[10px] uppercase tracking-widest text-emerald-400 font-black">Knowledge Extracted</span>
                              <span className="text-2xl font-black tracking-tighter text-white">
                                {lastMetrics.total_findings || 0}<span className="text-sm ml-1 opacity-50 uppercase">facts</span>
                              </span>
                            </div>
                         </div>
                       ) : (
                         <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                           {[
                             { label: 'Vector Search', value: lastMetrics.vector_time_ms, color: 'text-white' },
                             { label: 'Graph Traversal', value: lastMetrics.graph_time_ms, color: 'text-white' },
                             { label: 'BM25 / Algos', value: lastMetrics.bm25_time_ms, color: 'text-white' },
                             { label: 'AI Synthesis', value: lastMetrics.synthesis_time_ms, color: 'text-primary' }
                           ].map((stat, i) => (
                             <div key={i} className="bg-white/5 p-4 rounded-2xl border border-white/5 flex flex-col gap-1">
                               <span className="text-[9px] uppercase tracking-widest text-neutral-500 font-black">{stat.label}</span>
                               <span className={cn("text-xl font-bold tracking-tight", stat.color)}>
                                 {typeof stat.value === 'number' ? stat.value.toFixed(1) : '—'}
                                 <span className="text-xs ml-0.5 opacity-50">ms</span>
                               </span>
                             </div>
                           ))}
                         </div>
                       )}
                      
                      {lastMetrics.web_search_used && (
                        <div className="mt-4 grid grid-cols-2 lg:grid-cols-4 gap-4">
                           <div className="bg-white/5 p-4 rounded-2xl border border-white/5 flex flex-col gap-1">
                             <span className="text-[9px] uppercase tracking-widest text-neutral-500 font-black">Web Search</span>
                             <span className="text-xl font-bold tracking-tight text-white flex items-center gap-1">
                                <Globe className="w-4 h-4 text-primary" />
                                {lastMetrics.web_search_time_ms?.toFixed(1)}<span className="text-xs ml-0.5 opacity-50">ms</span>
                             </span>
                           </div>
                           <div className="bg-white/5 p-4 rounded-2xl border border-white/5 flex flex-col gap-1 lg:col-span-3">
                             <span className="text-[9px] uppercase tracking-widest text-neutral-500 font-black">Providers Consulted</span>
                             <div className="flex flex-wrap gap-2 mt-1">
                                {Object.entries(lastMetrics.web_providers_used || {}).map(([key, count]) => (
                                  <span key={key} className="bg-white/10 px-2 py-1 rounded-lg text-[10px] font-bold text-neutral-300 border border-white/10">
                                    {key}: {count} results
                                  </span>
                                ))}
                             </div>
                           </div>
                        </div>
                      )}
                   </section>
                 ) : (
                   <div className="flex flex-col items-center justify-center h-48 text-neutral-500 gap-4">
                      <Activity className="w-12 h-12 opacity-20" />
                      <p className="text-sm font-bold uppercase tracking-widest">No metrics recorded yet</p>
                   </div>
                 )}

                 {history.filter(m => m.role === 'assistant' && m.metrics && m.metrics.total_time_ms != null).length > 0 && (
                   <section className="space-y-4">
                      <div className="flex items-center gap-2 px-1">
                        <Clock className="w-4 h-4 text-neutral-500" />
                        <h3 className="text-xs font-black uppercase tracking-[0.2em] text-neutral-400">Conversation History</h3>
                      </div>
                      <div className="space-y-2">
                         {history.filter(m => m.role === 'assistant' && m.metrics && m.metrics.total_time_ms != null).map((m, i) => (
                           <div 
                            key={i} 
                            className={cn(
                              "flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer group",
                              m.metrics === lastMetrics 
                                ? "bg-primary/10 border-primary/30" 
                                : "bg-white/5 border-white/5 hover:border-white/10"
                            )}
                            onClick={() => setLastMetrics(m.metrics || null)}
                           >
                              <div className="flex items-center gap-4">
                                <span className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center text-[10px] font-black text-neutral-500 border border-white/10 group-hover:text-white transition-colors">T{i+1}</span>
                                <div className="flex flex-col">
                                  <span className="text-sm font-bold text-neutral-200">{m.metrics?.total_time_ms != null ? `${m.metrics.total_time_ms.toFixed(0)}ms Total` : 'Deep Research'}</span>
                                  <span className="text-[9px] uppercase tracking-widest text-neutral-500 font-bold">{m.content.slice(0, 80).replace(/\*\*/g, '')}...</span>
                                </div>
                              </div>
                              <div className="flex gap-4">
                                 <div className="text-right flex flex-col">
                                   <span className="text-[9px] uppercase tracking-widest text-neutral-600 font-black">Mode</span>
                                   <span className="text-[10px] font-bold text-primary">{m.metrics?.mode}</span>
                                 </div>
                                 <Zap className={cn("w-4 h-4 mt-1 transition-colors", m.metrics === lastMetrics ? "text-primary" : "text-neutral-700")} />
                              </div>
                           </div>
                         ))}
                      </div>
                   </section>
                 )}
              </div>

              <div className="p-6 bg-white/5 border-t border-white/5 text-center">
                 <p className="text-[10px] text-neutral-500 uppercase tracking-[0.3em] font-black">
                   Advanced Retrieval Metrics System v1.0
                 </p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
      {/* Memory Viewer Overlay */}
      <AnimatePresence>
        {showMemoryViewer && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 backdrop-blur-xl bg-black/40"
          >
            <motion.div 
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="w-full max-w-5xl bg-[#0a0a0a] border border-white/10 rounded-3xl overflow-hidden shadow-[0_0_100px_rgba(147,51,234,0.15)] flex flex-col max-h-[90vh]"
            >
              {/* Header */}
              <div className="p-6 border-b border-white/5 flex justify-between items-center bg-white/5">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-purple-500/20 flex items-center justify-center border border-purple-500/30">
                    <Brain className="w-5 h-5 text-purple-400" />
                  </div>
                  <div>
                    <h2 className="text-lg font-bold text-white tracking-tight uppercase">Session Memory</h2>
                    <p className="text-[10px] text-neutral-500 uppercase tracking-widest font-bold">
                      {memoryDump?.stats ? `${memoryDump.stats.total_messages} messages · ${memoryDump.stats.total_fragments} fragments · ${memoryDump.stats.total_traces} traces` : 'Loading...'}
                    </p>
                  </div>
                </div>
                <button 
                  onClick={() => setShowMemoryViewer(false)}
                  className="p-2 hover:bg-white/5 rounded-xl transition-colors text-neutral-400"
                >
                  <X className="w-6 h-6" />
                </button>
              </div>

              {/* Tabs */}
              <div className="flex border-b border-white/5 bg-white/[0.02]">
                {([
                  { key: 'conversation' as const, label: 'Conversation', icon: MessageSquare },
                  { key: 'fragments' as const, label: 'Fragments', icon: Database },
                  { key: 'web' as const, label: 'Web History', icon: Globe },
                  { key: 'traces' as const, label: 'Traces', icon: Search },
                ]).map(tab => (
                  <button
                    key={tab.key}
                    onClick={() => setMemoryTab(tab.key)}
                    className={cn(
                      "flex-1 flex items-center justify-center gap-2 px-4 py-3 text-[10px] uppercase tracking-widest font-black transition-all border-b-2",
                      memoryTab === tab.key
                        ? "border-purple-500 text-purple-400 bg-purple-500/5"
                        : "border-transparent text-neutral-500 hover:text-neutral-300 hover:bg-white/5"
                    )}
                  >
                    <tab.icon className="w-3.5 h-3.5" />
                    {tab.label}
                    {memoryDump && (
                      <span className="ml-1 text-[8px] opacity-60">
                        {tab.key === 'conversation' && memoryDump.stats?.total_messages}
                        {tab.key === 'fragments' && memoryDump.stats?.total_fragments}
                        {tab.key === 'web' && memoryDump.stats?.total_web_searches}
                        {tab.key === 'traces' && memoryDump.stats?.total_traces}
                      </span>
                    )}
                  </button>
                ))}
              </div>

              {/* Tab Content */}
              <div className="flex-1 overflow-y-auto p-6 space-y-4">
                {memoryLoading ? (
                  <div className="flex flex-col items-center justify-center h-48 text-neutral-500 gap-4">
                    <Brain className="w-12 h-12 opacity-20 animate-pulse" />
                    <p className="text-sm font-bold uppercase tracking-widest">Loading memory...</p>
                  </div>
                ) : !memoryDump ? (
                  <div className="flex flex-col items-center justify-center h-48 text-neutral-500 gap-4">
                    <Brain className="w-12 h-12 opacity-20" />
                    <p className="text-sm font-bold uppercase tracking-widest">Failed to load memory</p>
                  </div>
                ) : (
                  <>
                    {/* Conversation Tab */}
                    {memoryTab === 'conversation' && (
                      <div className="space-y-3">
                        {memoryDump.conversation_log.length === 0 ? (
                          <p className="text-center text-neutral-500 text-sm py-8">No messages in this session yet.</p>
                        ) : (
                          memoryDump.conversation_log.map((msg: any, i: number) => (
                            <div key={i} className={cn(
                              "p-4 rounded-2xl border relative group",
                              msg.role === 'user' 
                                ? "bg-primary/5 border-primary/20" 
                                : "bg-white/5 border-white/5"
                            )}>
                              <button
                                onClick={() => handleDeleteMemoryItem('conversation', msg.id)}
                                className="absolute top-2 right-2 p-1.5 rounded-lg bg-black/20 text-neutral-500 hover:text-red-400 hover:bg-red-500/10 opacity-0 group-hover:opacity-100 transition-all"
                                title="Delete message"
                              >
                                <Trash2 className="w-3.5 h-3.5" />
                              </button>
                              <div className="flex items-center gap-2 mb-2">
                                <span className={cn(
                                  "text-[9px] uppercase tracking-widest font-black px-2 py-0.5 rounded-md",
                                  msg.role === 'user' ? "bg-primary/20 text-primary" : "bg-white/10 text-neutral-400"
                                )}>
                                  {msg.role}
                                </span>
                                {msg.timestamp && (
                                  <span className="text-[9px] text-neutral-600">{new Date(msg.timestamp).toLocaleString()}</span>
                                )}
                              </div>
                              <p className="text-sm text-neutral-300 whitespace-pre-wrap leading-relaxed">{msg.content.length > 500 ? msg.content.slice(0, 500) + '...' : msg.content}</p>
                            </div>
                          ))
                        )}
                      </div>
                    )}

                    {/* Fragments Tab */}
                    {memoryTab === 'fragments' && (
                      <div className="space-y-3">
                        {memoryDump.fragments.length === 0 ? (
                          <p className="text-center text-neutral-500 text-sm py-8">No memory fragments extracted yet.</p>
                        ) : (
                          memoryDump.fragments.map((frag: any, i: number) => (
                            <div key={i} className="p-4 rounded-2xl bg-white/5 border border-white/5 space-y-2 relative group">
                              <button
                                onClick={() => handleDeleteMemoryItem('fragments', frag.fragment_id)}
                                className="absolute top-2 right-2 p-1.5 rounded-lg bg-black/20 text-neutral-500 hover:text-red-400 hover:bg-red-500/10 opacity-0 group-hover:opacity-100 transition-all"
                                title="Delete fragment"
                              >
                                <Trash2 className="w-3.5 h-3.5" />
                              </button>
                              <div className="flex items-center gap-2 flex-wrap">
                                <span className="text-[9px] uppercase tracking-widest font-black bg-purple-500/20 text-purple-400 px-2 py-0.5 rounded-md">
                                  {frag.fragment_type}
                                </span>
                                <span className="text-[9px] text-neutral-500">Score: {(frag.importance_score || 0).toFixed(2)}</span>
                                <span className="text-[9px] text-neutral-600">Accesses: {frag.access_count || 0}</span>
                                {frag.tags && frag.tags.length > 0 && (
                                  <div className="flex gap-1">
                                    {frag.tags.map((tag: string, j: number) => (
                                      <span key={j} className="text-[8px] bg-white/10 text-neutral-400 px-1.5 py-0.5 rounded">{tag}</span>
                                    ))}
                                  </div>
                                )}
                              </div>
                              <p className="text-sm text-neutral-300 leading-relaxed">{frag.content}</p>
                              {frag.created_at && (
                                <p className="text-[9px] text-neutral-600">{new Date(frag.created_at).toLocaleString()}</p>
                              )}
                            </div>
                          ))
                        )}
                      </div>
                    )}

                    {/* Web History Tab */}
                    {memoryTab === 'web' && (
                      <div className="space-y-3">
                        {memoryDump.web_history.length === 0 ? (
                          <p className="text-center text-neutral-500 text-sm py-8">No web searches performed in this session.</p>
                        ) : (
                          memoryDump.web_history.map((log: any, i: number) => (
                            <div key={i} className="p-4 rounded-2xl bg-white/5 border border-white/5 space-y-1 relative group">
                              <button
                                onClick={() => handleDeleteMemoryItem('web', log.id)}
                                className="absolute top-2 right-2 p-1.5 rounded-lg bg-black/20 text-neutral-500 hover:text-red-400 hover:bg-red-500/10 opacity-0 group-hover:opacity-100 transition-all"
                                title="Delete log"
                              >
                                <Trash2 className="w-3.5 h-3.5" />
                              </button>
                              <div className="flex items-center gap-2">
                                <Globe className="w-3 h-3 text-primary" />
                                <span className="text-[9px] uppercase tracking-widest font-black bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded-md">
                                  {log.provider}
                                </span>
                                <span className="text-[9px] text-neutral-500">Turn {log.turn_index}</span>
                                {log.relevance_score > 0 && (
                                  <span className="text-[9px] text-neutral-500">Score: {log.relevance_score.toFixed(2)}</span>
                                )}
                              </div>
                              <p className="text-xs text-neutral-400">Query: &quot;{log.query_sent}&quot;</p>
                              {log.title && <p className="text-sm text-neutral-200 font-medium">{log.title}</p>}
                              {log.url && (
                                <a href={log.url} target="_blank" rel="noopener noreferrer" className="text-xs text-primary hover:underline break-all">{log.url}</a>
                              )}
                              {log.snippet && <p className="text-xs text-neutral-400 leading-relaxed">{log.snippet}</p>}
                            </div>
                          ))
                        )}
                      </div>
                    )}

                    {/* Traces Tab */}
                    {memoryTab === 'traces' && (
                      <div className="space-y-3">
                        {memoryDump.reasoning_traces.length === 0 ? (
                          <p className="text-center text-neutral-500 text-sm py-8">No reasoning traces recorded yet.</p>
                        ) : (
                          memoryDump.reasoning_traces.map((trace: any, i: number) => (
                            <div key={i} className="p-4 rounded-2xl bg-white/5 border border-white/5 space-y-3 relative group">
                              <button
                                onClick={() => handleDeleteMemoryItem('traces', trace.id)}
                                className="absolute top-2 right-2 p-1.5 rounded-lg bg-black/20 text-neutral-500 hover:text-red-400 hover:bg-red-500/10 opacity-0 group-hover:opacity-100 transition-all"
                                title="Delete trace"
                              >
                                <Trash2 className="w-3.5 h-3.5" />
                              </button>
                              <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                  <span className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center text-[10px] font-black text-neutral-500 border border-white/10">T{trace.turn_index + 1}</span>
                                  <span className="text-sm font-bold text-neutral-200">{trace.total_time_ms?.toFixed(0)}ms</span>
                                  {trace.web_search_triggered && <Globe className="w-3 h-3 text-blue-400" />}
                                </div>
                                <span className="text-[9px] text-neutral-600">{trace.created_at ? new Date(trace.created_at).toLocaleString() : ''}</span>
                              </div>
                              <div className="space-y-1">
                                <p className="text-xs text-neutral-400"><span className="font-bold text-neutral-300">Query:</span> {trace.user_query}</p>
                                {trace.reformulated_query && trace.reformulated_query !== trace.user_query && (
                                  <p className="text-xs text-neutral-500"><span className="font-bold text-neutral-400">Reformulated:</span> {trace.reformulated_query}</p>
                                )}
                                {trace.algorithms_used && trace.algorithms_used.length > 0 && (
                                  <div className="flex flex-wrap gap-1 mt-1">
                                    {trace.algorithms_used.map((algo: string, j: number) => (
                                      <span key={j} className="text-[8px] bg-primary/10 text-primary px-1.5 py-0.5 rounded border border-primary/20 font-bold uppercase">{algo}</span>
                                    ))}
                                  </div>
                                )}
                                {trace.answer_summary && (
                                  <p className="text-xs text-neutral-400 mt-1"><span className="font-bold text-neutral-300">Summary:</span> {trace.answer_summary.slice(0, 200)}{trace.answer_summary.length > 200 ? '...' : ''}</p>
                                )}
                              </div>
                            </div>
                          ))
                        )}
                      </div>
                    )}
                  </>
                )}
              </div>

              {/* Footer */}
              <div className="p-6 bg-white/5 border-t border-white/5 text-center">
                <p className="text-[10px] text-neutral-500 uppercase tracking-[0.3em] font-black">
                  Memory Architecture System v1.0
                </p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* LLM Judge Viewer Overlay */}
      <AnimatePresence>
        {showJudgeViewer && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 backdrop-blur-xl bg-black/40"
          >
            <motion.div 
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="w-full max-w-5xl bg-[#0a0a0a] border border-white/10 rounded-3xl overflow-hidden shadow-[0_0_100px_rgba(245,158,11,0.1)] flex flex-col max-h-[90vh]"
            >
              {/* Header */}
              <div className="p-6 border-b border-white/5 flex justify-between items-center bg-white/5">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-amber-500/20 flex items-center justify-center border border-amber-500/30">
                    <Scale className="w-5 h-5 text-amber-400" />
                  </div>
                  <div>
                    <h2 className="text-lg font-bold text-white tracking-tight uppercase">LLM Judge</h2>
                    <p className="text-[10px] text-neutral-500 uppercase tracking-widest font-bold">
                      {judgeEvaluations.length} evaluation{judgeEvaluations.length !== 1 ? 's' : ''} recorded
                    </p>
                  </div>
                </div>
                <button 
                  onClick={() => setShowJudgeViewer(false)}
                  className="p-2 hover:bg-white/5 rounded-xl transition-colors text-neutral-400"
                >
                  <X className="w-6 h-6" />
                </button>
              </div>

              {/* Content */}
              <div className="flex-1 overflow-y-auto p-6 space-y-6">
                {judgeLoading ? (
                  <div className="flex flex-col items-center justify-center h-48 text-neutral-500 gap-4">
                    <Scale className="w-12 h-12 opacity-20 animate-pulse" />
                    <p className="text-sm font-bold uppercase tracking-widest">Loading evaluations...</p>
                  </div>
                ) : judgeEvaluations.length === 0 ? (
                  <div className="flex flex-col items-center justify-center h-48 text-neutral-500 gap-4">
                    <Scale className="w-12 h-12 opacity-20" />
                    <p className="text-sm font-bold uppercase tracking-widest">No evaluations yet</p>
                    <p className="text-xs text-neutral-600 max-w-md text-center">Click the "Evaluate" button on any assistant response to get an LLM-powered quality assessment.</p>
                  </div>
                ) : (
                  <>
                    {/* Selected Evaluation Detail */}
                    {selectedEvaluation && (
                      <section className="space-y-4">
                        <div className="flex items-center gap-2 px-1">
                          <Star className="w-4 h-4 text-amber-400" />
                          <h3 className="text-xs font-black uppercase tracking-[0.2em] text-neutral-400">Evaluation Detail</h3>
                        </div>

                        {/* Verdict Badge */}
                        <div className="flex items-center gap-4">
                          <div className={cn(
                            "px-4 py-2 rounded-xl text-sm font-black uppercase tracking-widest border",
                            selectedEvaluation.verdict === 'excellent' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
                            selectedEvaluation.verdict === 'good' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' :
                            selectedEvaluation.verdict === 'fair' ? 'bg-amber-500/10 text-amber-400 border-amber-500/20' :
                            'bg-red-500/10 text-red-400 border-red-500/20'
                          )}>
                            {selectedEvaluation.verdict}
                          </div>
                          <div className="flex flex-col">
                            <span className="text-2xl font-black tracking-tighter text-white">
                              {selectedEvaluation.overall_score}<span className="text-sm ml-0.5 opacity-50">/10</span>
                            </span>
                            <span className="text-[9px] uppercase tracking-widest text-neutral-500 font-black">Overall Score</span>
                          </div>
                          <div className="ml-auto text-[9px] text-neutral-600">
                            {selectedEvaluation.evaluation_time_ms?.toFixed(0)}ms evaluation time
                          </div>
                        </div>

                        {/* Dimension Scores */}
                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
                          {[
                            { key: 'relevance', label: 'Relevance', color: 'text-blue-400 bg-blue-500/10 border-blue-500/20' },
                            { key: 'accuracy', label: 'Accuracy', color: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/20' },
                            { key: 'completeness', label: 'Completeness', color: 'text-purple-400 bg-purple-500/10 border-purple-500/20' },
                            { key: 'clarity', label: 'Clarity', color: 'text-cyan-400 bg-cyan-500/10 border-cyan-500/20' },
                            { key: 'depth', label: 'Depth', color: 'text-indigo-400 bg-indigo-500/10 border-indigo-500/20' },
                            { key: 'conciseness', label: 'Conciseness', color: 'text-pink-400 bg-pink-500/10 border-pink-500/20' },
                            { key: 'helpfulness', label: 'Helpfulness', color: 'text-amber-400 bg-amber-500/10 border-amber-500/20' },
                            { key: 'factual_grounding', label: 'Factual Ground.', color: 'text-teal-400 bg-teal-500/10 border-teal-500/20' },
                            { key: 'coherence', label: 'Coherence', color: 'text-violet-400 bg-violet-500/10 border-violet-500/20' },
                            { key: 'engagement', label: 'Engagement', color: 'text-rose-400 bg-rose-500/10 border-rose-500/20' },
                            { key: 'safety', label: 'Safety', color: 'text-lime-400 bg-lime-500/10 border-lime-500/20' },
                          ].map(dim => {
                            const score = (selectedEvaluation as any)[dim.key] as number;
                            return (
                              <div key={dim.key} className={cn("p-3 rounded-xl border flex flex-col gap-1", dim.color)}>
                                <span className="text-[9px] uppercase tracking-widest font-black opacity-80">{dim.label}</span>
                                <div className="flex items-end gap-2">
                                  <span className="text-xl font-black tracking-tight text-white">{score ?? '—'}</span>
                                  <div className="flex-1 h-1.5 bg-white/10 rounded-full overflow-hidden">
                                    <div 
                                      className={cn("h-full rounded-full transition-all duration-500", 
                                        (score ?? 0) >= 8 ? 'bg-emerald-400' : (score ?? 0) >= 6 ? 'bg-blue-400' : (score ?? 0) >= 4 ? 'bg-amber-400' : 'bg-red-400'
                                      )} 
                                      style={{ width: `${((score ?? 0) / 10) * 100}%` }} 
                                    />
                                  </div>
                                </div>
                              </div>
                            );
                          })}
                        </div>

                        {/* Reasoning */}
                        {selectedEvaluation.reasoning && (
                          <div className="p-4 rounded-2xl bg-white/5 border border-white/5">
                            <span className="text-[9px] uppercase tracking-widest font-black text-neutral-500 block mb-1">Judge Reasoning</span>
                            <p className="text-sm text-neutral-300 leading-relaxed italic">{selectedEvaluation.reasoning}</p>
                          </div>
                        )}

                        {/* Strengths / Weaknesses / Suggestions */}
                        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
                          {selectedEvaluation.strengths?.length > 0 && (
                            <div className="p-4 rounded-2xl bg-emerald-500/5 border border-emerald-500/10 space-y-2">
                              <div className="flex items-center gap-2">
                                <CheckCircle2 className="w-3.5 h-3.5 text-emerald-400" />
                                <span className="text-[9px] uppercase tracking-widest font-black text-emerald-400">Strengths</span>
                              </div>
                              <ul className="space-y-1">
                                {selectedEvaluation.strengths.map((s, i) => (
                                  <li key={i} className="text-xs text-neutral-300 leading-relaxed">• {s}</li>
                                ))}
                              </ul>
                            </div>
                          )}
                          {selectedEvaluation.weaknesses?.length > 0 && (
                            <div className="p-4 rounded-2xl bg-red-500/5 border border-red-500/10 space-y-2">
                              <div className="flex items-center gap-2">
                                <AlertTriangle className="w-3.5 h-3.5 text-red-400" />
                                <span className="text-[9px] uppercase tracking-widest font-black text-red-400">Weaknesses</span>
                              </div>
                              <ul className="space-y-1">
                                {selectedEvaluation.weaknesses.map((w, i) => (
                                  <li key={i} className="text-xs text-neutral-300 leading-relaxed">• {w}</li>
                                ))}
                              </ul>
                            </div>
                          )}
                          {selectedEvaluation.suggestions?.length > 0 && (
                            <div className="p-4 rounded-2xl bg-amber-500/5 border border-amber-500/10 space-y-2">
                              <div className="flex items-center gap-2">
                                <Lightbulb className="w-3.5 h-3.5 text-amber-400" />
                                <span className="text-[9px] uppercase tracking-widest font-black text-amber-400">Suggestions</span>
                              </div>
                              <ul className="space-y-1">
                                {selectedEvaluation.suggestions.map((s, i) => (
                                  <li key={i} className="text-xs text-neutral-300 leading-relaxed">• {s}</li>
                                ))}
                              </ul>
                            </div>
                          )}
                        </div>
                      </section>
                    )}

                    {/* Evaluation History */}
                    {judgeEvaluations.length > 0 && (
                      <section className="space-y-4">
                        <div className="flex items-center gap-2 px-1">
                          <Clock className="w-4 h-4 text-neutral-500" />
                          <h3 className="text-xs font-black uppercase tracking-[0.2em] text-neutral-400">Evaluation History</h3>
                        </div>
                        <div className="space-y-2">
                          {judgeEvaluations.map((ev, i) => (
                            <div 
                              key={ev.id || i}
                              className={cn(
                                "flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer group relative",
                                ev === selectedEvaluation
                                  ? "bg-amber-500/10 border-amber-500/30"
                                  : "bg-white/5 border-white/5 hover:border-white/10"
                              )}
                              onClick={() => setSelectedEvaluation(ev)}
                            >
                              {/* Delete button */}
                              <button
                                onClick={async (e) => {
                                  e.stopPropagation();
                                  if (!ev.id) return;
                                  try {
                                    await api.deleteEvaluation(ev.id);
                                    setJudgeEvaluations(prev => prev.filter(e => e.id !== ev.id));
                                    if (selectedEvaluation?.id === ev.id) {
                                      setSelectedEvaluation(judgeEvaluations.length > 1 ? judgeEvaluations.find(e => e.id !== ev.id) || null : null);
                                    }
                                    showNotification({ type: 'success', title: 'Deleted', message: 'Evaluation removed.' });
                                  } catch (err) {
                                    console.error('Failed to delete evaluation:', err);
                                    showNotification({ type: 'error', title: 'Error', message: 'Could not delete evaluation.' });
                                  }
                                }}
                                className="absolute top-2 right-2 p-1.5 rounded-lg bg-black/20 text-neutral-500 hover:text-red-400 hover:bg-red-500/10 opacity-0 group-hover:opacity-100 transition-all"
                                title="Delete evaluation"
                              >
                                <Trash2 className="w-3.5 h-3.5" />
                              </button>
                              <div className="flex items-center gap-4">
                                <span className={cn(
                                  "w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black border",
                                  ev.verdict === 'excellent' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
                                  ev.verdict === 'good' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' :
                                  ev.verdict === 'fair' ? 'bg-amber-500/10 text-amber-400 border-amber-500/20' :
                                  'bg-red-500/10 text-red-400 border-red-500/20'
                                )}>
                                  {ev.overall_score}
                                </span>
                                <div className="flex flex-col">
                                  <span className="text-sm font-bold text-neutral-200">
                                    {ev.verdict?.toUpperCase()} — {ev.overall_score}/10
                                  </span>
                                  <span className="text-[9px] uppercase tracking-widest text-neutral-500 font-bold">
                                    {ev.user_query ? ev.user_query.slice(0, 80) + (ev.user_query.length > 80 ? '...' : '') : `Response #${(ev.message_index ?? i) + 1}`}
                                  </span>
                                </div>
                              </div>
                              <div className="flex gap-2 items-center pr-6">
                                <span className="text-[9px] text-neutral-600">{ev.evaluation_time_ms?.toFixed(0)}ms</span>
                                <Scale className={cn("w-4 h-4 transition-colors", ev === selectedEvaluation ? 'text-amber-400' : 'text-neutral-700')} />
                              </div>
                            </div>
                          ))}
                        </div>
                      </section>
                    )}
                  </>
                )}
              </div>

              {/* Footer */}
              <div className="p-6 bg-white/5 border-t border-white/5 text-center">
                <p className="text-[10px] text-neutral-500 uppercase tracking-[0.3em] font-black">
                  LLM-as-a-Judge Quality Assessment System v2.0 · 11 Dimensions
                </p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';

import React, { useMemo } from 'react';
import { CostAnalytics } from '@/lib/api';

type CostDashboardProps = {
  data: CostAnalytics | null;
};

const COLORS = ['#a78bfa', '#60a5fa', '#34d399', '#f59e0b', '#f472b6', '#22c55e', '#fca5a5', '#38bdf8'];

function formatUsd(n: number) {
  if (!isFinite(n)) return '$0.00';
  return n.toLocaleString(undefined, { style: 'currency', currency: 'USD', maximumFractionDigits: 4 });
}

function formatInt(n: number) {
  if (!isFinite(n)) return '0';
  return Math.round(n).toLocaleString();
}

export default function CostDashboard({ data }: CostDashboardProps) {
  const daily = data?.daily_spend || [];
  const provider = data?.provider_breakdown || [];
  const topSessions = data?.top_sessions || [];
  const summary = data?.summary;

  const totalCost = summary?.total_cost_usd ?? 0;
  const totalCalls = summary?.total_calls ?? 0;
  const avgCost = totalCalls > 0 ? totalCost / totalCalls : 0;

  const dailySeries = useMemo(() => {
    const pts = daily.map((d) => d.cost_usd);
    const max = Math.max(0, ...pts);
    return { pts, max };
  }, [daily]);

  const gradientStyle = useMemo(() => {
    const total = provider.reduce((acc, p) => acc + (p.cost_usd || 0), 0);
    if (total <= 0) return { background: 'conic-gradient(#334155 0deg 360deg)' };

    let accPct = 0;
    const parts = provider.slice(0, 8).map((p, i) => {
      const pct = ((p.cost_usd || 0) / total) * 100;
      const start = accPct;
      const end = accPct + pct;
      accPct = end;
      const c = COLORS[i % COLORS.length];
      return `${c} ${start.toFixed(2)}% ${end.toFixed(2)}%`;
    });
    return { background: `conic-gradient(${parts.join(', ')})` };
  }, [provider]);

  if (!data) {
    return (
      <div className="text-xs text-neutral-500">
        No analytics yet.
      </div>
    );
  }

  const hasNoData = (summary?.total_calls ?? 0) === 0;

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-white/5 border border-white/10 p-4 rounded-2xl">
          <div className="text-[10px] uppercase tracking-widest text-neutral-500 font-black">Total Cost</div>
          <div className="text-2xl font-black text-white mt-1">{formatUsd(summary?.total_cost_usd ?? 0)}</div>
          <div className="text-[10px] text-neutral-500 mt-1 uppercase tracking-widest">avg {formatUsd(avgCost)} / call</div>
        </div>
        <div className="bg-white/5 border border-white/10 p-4 rounded-2xl">
          <div className="text-[10px] uppercase tracking-widest text-neutral-500 font-black">Input Tokens</div>
          <div className="text-2xl font-black text-white mt-1">{formatInt(summary?.total_input_tokens ?? 0)}</div>
        </div>
        <div className="bg-white/5 border border-white/10 p-4 rounded-2xl">
          <div className="text-[10px] uppercase tracking-widest text-neutral-500 font-black">Output Tokens</div>
          <div className="text-2xl font-black text-white mt-1">{formatInt(summary?.total_output_tokens ?? 0)}</div>
        </div>
        <div className="bg-white/5 border border-white/10 p-4 rounded-2xl">
          <div className="text-[10px] uppercase tracking-widest text-neutral-500 font-black">Calls</div>
          <div className="text-2xl font-black text-white mt-1">{formatInt(summary?.total_calls ?? 0)}</div>
          <div className="text-[10px] text-neutral-500 mt-1 uppercase tracking-widest">range: {data.range_days} days</div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="bg-white/5 border border-white/10 rounded-2xl p-4">
          <div className="flex items-center justify-between mb-3">
            <div className="text-sm font-bold text-white">Daily Spend</div>
            <div className="text-[10px] uppercase tracking-widest text-neutral-500">
              {daily.length ? `${daily[0].date} → ${daily[daily.length - 1].date}` : 'No data'}
            </div>
          </div>
          {hasNoData ? (
            <div className="text-xs text-neutral-500">Token/cost data will appear after the next LLM calls.</div>
          ) : (
            <svg viewBox="0 0 600 220" className="w-full h-auto">
              <defs>
                <linearGradient id="costLine" x1="0" y1="0" x2="1" y2="0">
                  <stop offset="0%" stopColor="#60a5fa" stopOpacity="0.8" />
                  <stop offset="100%" stopColor="#a78bfa" stopOpacity="0.9" />
                </linearGradient>
              </defs>
              {/* grid */}
              {[0.25, 0.5, 0.75].map((p, i) => (
                <line
                  key={i}
                  x1={50}
                  y1={180 - 180 * p}
                  x2={580}
                  y2={180 - 180 * p}
                  stroke="rgba(255,255,255,0.08)"
                  strokeWidth="1"
                />
              ))}

              {daily.length > 1 ? (
                (() => {
                  const max = dailySeries.max || 1;
                  const paddingLeft = 50;
                  const paddingRight = 20;
                  const plotWidth = 600 - paddingLeft - paddingRight;
                  const plotHeight = 180;
                  const points = daily.map((d, idx) => {
                    const x = paddingLeft + (idx / (daily.length - 1)) * plotWidth;
                    const y = 200 - (d.cost_usd / max) * plotHeight;
                    return { x, y, v: d.cost_usd };
                  });
                  const poly = points.map((p) => `${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(' ');

                  return (
                    <>
                      <polyline
                        fill="none"
                        stroke="url(#costLine)"
                        strokeWidth="3"
                        strokeLinejoin="round"
                        strokeLinecap="round"
                        points={poly}
                      />
                      {points.map((p, i) => (
                        <circle
                          key={i}
                          cx={p.x}
                          cy={p.y}
                          r="4"
                          fill="#0b0b0f"
                          stroke="rgba(167,139,250,0.9)"
                          strokeWidth="2"
                        />
                      ))}
                    </>
                  );
                })()
              ) : (
                <text x="50" y="120" fill="rgba(255,255,255,0.6)" fontSize="12">
                  Not enough data for a trend line.
                </text>
              )}
              <text x="50" y="205" fill="rgba(255,255,255,0.45)" fontSize="11">Spend</text>
            </svg>
          )}
        </div>

        <div className="bg-white/5 border border-white/10 rounded-2xl p-4">
          <div className="flex items-center justify-between mb-3">
            <div className="text-sm font-bold text-white">Provider Breakdown</div>
            <div className="text-[10px] uppercase tracking-widest text-neutral-500">{provider.length ? 'By cost' : 'No data'}</div>
          </div>

          {hasNoData ? (
            <div className="text-xs text-neutral-500">Provider breakdown will appear as usage is logged.</div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 items-center">
              <div className="flex items-center justify-center">
                <div
                  className="rounded-full w-40 h-40 border border-white/10 flex items-center justify-center"
                  style={{
                    ...gradientStyle,
                  }}
                >
                  <div className="text-center">
                    <div className="text-xs uppercase tracking-widest text-neutral-400">Total</div>
                    <div className="text-lg font-black text-white">{formatUsd(totalCost)}</div>
                  </div>
                </div>
              </div>
              <div className="space-y-2">
                {provider.slice(0, 6).map((p, i) => {
                  const c = COLORS[i % COLORS.length];
                  return (
                    <div key={p.provider} className="flex items-center justify-between gap-4">
                      <div className="flex items-center gap-2 min-w-[0px]">
                        <span className="w-2.5 h-2.5 rounded-full" style={{ background: c }} />
                        <span className="text-xs font-bold text-neutral-200 truncate">{p.provider}</span>
                      </div>
                      <span className="text-xs text-neutral-400 font-mono">{formatUsd(p.cost_usd)}</span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="bg-white/5 border border-white/10 rounded-2xl p-4">
        <div className="flex items-center justify-between mb-3">
          <div className="text-sm font-bold text-white">Top Sessions</div>
          <div className="text-[10px] uppercase tracking-widest text-neutral-500">{topSessions.length ? 'By cost' : 'No data'}</div>
        </div>

        {hasNoData ? (
          <div className="text-xs text-neutral-500">Top sessions appear once enough LLM logs exist.</div>
        ) : (
          <div className="space-y-3">
            <div className="flex gap-4 items-end">
              {(() => {
                const max = Math.max(1, ...topSessions.map((s) => s.cost_usd || 0));
                return topSessions.map((s, i) => {
                  const c = COLORS[i % COLORS.length];
                  const pct = (s.cost_usd || 0) / max;
                  return (
                    <div key={s.chat_id} className="flex-1 min-w-[90px]">
                      <div
                        className="w-full rounded-xl border border-white/10"
                        style={{
                          height: `${Math.max(18, pct * 150)}px`,
                          background: `linear-gradient(180deg, ${c}33, ${c}10)`,
                        }}
                        title={`${s.title} (${formatUsd(s.cost_usd)})`}
                      />
                      <div className="mt-2 text-[10px] text-neutral-500 truncate" title={s.title}>
                        {s.title}
                      </div>
                      <div className="text-[10px] text-neutral-400 font-mono mt-1">{formatUsd(s.cost_usd)}</div>
                    </div>
                  );
                });
              })()}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

