'use client';

import React, { useState, useEffect, useRef } from 'react';
import {
  Search, Square, CheckCircle2, Circle, Loader2,
  Globe, Brain, FileText, ChevronDown, ChevronUp,
  AlertCircle, Microscope, XCircle
} from 'lucide-react';

// ─────────────────────────────────────────────────
// Types
// ─────────────────────────────────────────────────

interface ResearchProgressEvent {
  event_type: string;
  step_index?: number | null;
  total_steps?: number | null;
  sources_scraped: number;
  total_findings: number;
  current_activity: string;
  thinking?: string | null;
  data?: Record<string, any> | null;
  timestamp?: string;
}

interface ResearchStep {
  index: number;
  title: string;
  status: 'pending' | 'running' | 'completed' | 'error';
}

// ─────────────────────────────────────────────────
// Props
// ─────────────────────────────────────────────────

interface DeepResearchPanelProps {
  sessionId: string;
  query: string;
  onComplete: (report: string, sources: string[], metrics?: any) => void;
  onCancel: () => void;
  apiBaseUrl: string;
}

// ─────────────────────────────────────────────────
// Component
// ─────────────────────────────────────────────────

export default function DeepResearchPanel({
  sessionId,
  query,
  onComplete,
  onCancel,
  apiBaseUrl,
}: DeepResearchPanelProps) {
  const [status, setStatus] = useState<string>('planning');
  const [steps, setSteps] = useState<ResearchStep[]>([]);
  const [sourceCount, setSourceCount] = useState(0);
  const [findingsCount, setFindingsCount] = useState(0);
  const [currentActivity, setCurrentActivity] = useState('Starting research...');
  const [thinking, setThinking] = useState<string | null>(null);
  const [activityLog, setActivityLog] = useState<{ text: string; icon: string; time: string }[]>([]);
  const [progress, setProgress] = useState(0);
  const [showSteps, setShowSteps] = useState(true);
  const [isStopping, setIsStopping] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const activityRef = useRef<HTMLDivElement>(null);
  const pollingRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const hasCompletedRef = useRef(false);

  // Auto-scroll activity feed
  useEffect(() => {
    if (activityRef.current) {
      activityRef.current.scrollTop = activityRef.current.scrollHeight;
    }
  }, [activityLog]);

  // Poll for status updates
  useEffect(() => {
    let lastEventCount = 0;

    const poll = async () => {
      try {
        const res = await fetch(`${apiBaseUrl}/research/${sessionId}/status`);
        if (!res.ok) return;
        const data = await res.json();

        setStatus(data.status);
        setSourceCount(data.sources_scraped || 0);
        setFindingsCount(data.total_findings || 0);

        // Process new events
        const events: ResearchProgressEvent[] = data.progress_events || [];
        const newEvents = events.slice(lastEventCount);
        lastEventCount = events.length;

        for (const evt of newEvents) {
          processEvent(evt);
        }

        // Update plan steps
        if (data.plan?.steps) {
          const planSteps: ResearchStep[] = data.plan.steps.map((s: any) => ({
            index: s.step_index,
            title: s.title,
            status: s.status || 'pending',
          }));
          // Merge with current step state
          setSteps(prev => {
            const merged = planSteps.map((ps: ResearchStep) => {
              const existing = prev.find(p => p.index === ps.index);
              return existing ? { ...ps, status: existing.status } : ps;
            });
            return merged;
          });
        }

        // Check completion
        if (['complete', 'cancelled', 'error'].includes(data.status)) {
          if (pollingRef.current) {
            clearInterval(pollingRef.current);
            pollingRef.current = null;
          }

          if (hasCompletedRef.current) return;

          if (data.status === 'error') {
            setError('Research encountered an error.');
            hasCompletedRef.current = true; // Allow the error state to trigger once
          }

          // Fetch the final result
          try {
            const resultRes = await fetch(`${apiBaseUrl}/research/${sessionId}/result`);
            if (resultRes.ok) {
              const resultData = await resultRes.json();
              if (resultData.report && !hasCompletedRef.current) {
                hasCompletedRef.current = true;
                // Extract unique source URLs
                const sources = resultData.sources 
                  ? Array.from(new Set(resultData.sources.map((s: any) => s.url))).filter(Boolean) as string[]
                  : [];
                onComplete(resultData.report, sources, {
                  type: 'deep_research',
                  total_time_ms: resultData.research_time_ms,
                  total_sources: resultData.total_sources,
                  total_findings: resultData.total_findings,
                  session_id: sessionId
                });
              }
            }
          } catch {
            if (!hasCompletedRef.current) {
              hasCompletedRef.current = true;
              onComplete('Research completed but failed to fetch results.', [], { type: 'deep_research', error: true });
            }
          }
        }

      } catch (err) {
        console.error('Polling error:', err);
      }
    };

    // Start polling
    poll(); // Initial fetch
    pollingRef.current = setInterval(poll, 2000);

    return () => {
      if (pollingRef.current) {
        clearInterval(pollingRef.current);
      }
    };
  }, [sessionId, apiBaseUrl]);

  const processEvent = (evt: ResearchProgressEvent) => {
    if (evt.current_activity) {
      setCurrentActivity(evt.current_activity);
    }
    if (evt.thinking) {
      setThinking(evt.thinking);
    }

    const time = evt.timestamp
      ? new Date(evt.timestamp).toLocaleTimeString()
      : new Date().toLocaleTimeString();

    switch (evt.event_type) {
      case 'plan_generated':
        if (evt.data?.steps) {
          setSteps(evt.data.steps.map((s: any) => ({
            index: s.index,
            title: s.title,
            status: 'pending' as const,
          })));
        }
        addActivity('📋 Research plan generated', time);
        break;

      case 'step_started':
        if (evt.step_index !== null && evt.step_index !== undefined) {
          setSteps(prev => prev.map(s =>
            s.index === evt.step_index
              ? { ...s, status: 'running' as const }
              : s.index < (evt.step_index || 0)
                ? { ...s, status: 'completed' as const }
                : s
          ));
          updateProgress(evt);
        }
        addActivity(`🔍 ${evt.current_activity}`, time);
        break;

      case 'search_completed':
        addActivity(`🔎 ${evt.current_activity}`, time);
        break;

      case 'source_scraped':
        setSourceCount(evt.sources_scraped);
        addActivity(`🌐 ${evt.current_activity}`, time);
        break;

      case 'analyzing_source':
        addActivity(`🧠 ${evt.current_activity}`, time);
        break;

      case 'findings_extracted':
        setFindingsCount(evt.total_findings);
        addActivity(`📝 ${evt.current_activity}`, time);
        break;

      case 'step_completed':
        if (evt.step_index !== null && evt.step_index !== undefined) {
          setSteps(prev => prev.map(s =>
            s.index === evt.step_index
              ? { ...s, status: 'completed' as const }
              : s
          ));
          updateProgress(evt);
        }
        addActivity(`✅ ${evt.current_activity}`, time);
        break;

      case 'synthesis_started':
        setStatus('synthesizing');
        addActivity('🧬 Synthesizing final research report...', time);
        break;

      case 'research_complete':
        setProgress(100);
        addActivity('✨ Research complete!', time);
        break;

      case 'error':
        setError(evt.current_activity);
        addActivity(`❌ ${evt.current_activity}`, time);
        break;

      default:
        if (evt.current_activity) {
          addActivity(`ℹ️ ${evt.current_activity}`, time);
        }
    }
  };

  const addActivity = (text: string, time: string) => {
    setActivityLog(prev => [...prev.slice(-50), { text, icon: '', time }]);
  };

  const updateProgress = (evt: ResearchProgressEvent) => {
    if (evt.step_index !== null && evt.step_index !== undefined && evt.total_steps) {
      const pct = Math.round(((evt.step_index + 1) / evt.total_steps) * 90);
      setProgress(pct);
    }
  };

  const handleStop = async () => {
    setIsStopping(true);
    try {
      await fetch(`${apiBaseUrl}/research/${sessionId}/stop`, { method: 'POST' });
    } catch (err) {
      console.error('Failed to stop research:', err);
    }
  };

  // ─────────────────────────────────────────────────
  // Status helpers
  // ─────────────────────────────────────────────────

  const getStatusLabel = () => {
    switch (status) {
      case 'planning': return 'Generating Research Plan';
      case 'researching': return 'Researching';
      case 'synthesizing': return 'Synthesizing Report';
      case 'stopping': return 'Stopping — Synthesizing Partial Findings';
      case 'complete': return 'Research Complete';
      case 'cancelled': return 'Research Stopped';
      case 'error': return 'Error';
      default: return 'Initializing';
    }
  };

  const getStatusColor = () => {
    switch (status) {
      case 'planning': return '#a78bfa';
      case 'researching': return '#60a5fa';
      case 'synthesizing': return '#f59e0b';
      case 'stopping': return '#fb923c';
      case 'complete': return '#34d399';
      case 'cancelled': return '#fb923c';
      case 'error': return '#f87171';
      default: return '#94a3b8';
    }
  };

  const getStepIcon = (stepStatus: string) => {
    switch (stepStatus) {
      case 'completed': return <CheckCircle2 size={16} color="#34d399" />;
      case 'running': return <Loader2 size={16} color="#60a5fa" className="animate-spin" />;
      case 'error': return <XCircle size={16} color="#f87171" />;
      default: return <Circle size={16} color="#4b5563" />;
    }
  };

  const isActive = !['complete', 'cancelled', 'error'].includes(status);
  const isStopped = status === 'stopping' || isStopping;

  // ─────────────────────────────────────────────────
  // Render
  // ─────────────────────────────────────────────────

  return (
    <div style={{
      background: 'linear-gradient(135deg, rgba(15, 23, 42, 0.95), rgba(30, 41, 59, 0.95))',
      border: '1px solid rgba(148, 163, 184, 0.15)',
      borderRadius: '16px',
      padding: '24px',
      margin: '8px 0',
      backdropFilter: 'blur(12px)',
      boxShadow: '0 8px 32px rgba(0, 0, 0, 0.3)',
    }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px' }}>
        <div style={{
          background: `linear-gradient(135deg, ${getStatusColor()}33, ${getStatusColor()}11)`,
          borderRadius: '12px',
          padding: '10px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}>
          <Microscope size={24} color={getStatusColor()} />
        </div>
        <div style={{ flex: 1 }}>
          <div style={{
            fontSize: '16px',
            fontWeight: 600,
            color: '#e2e8f0',
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
          }}>
            Deep Research
            <span style={{
              fontSize: '11px',
              fontWeight: 500,
              background: `${getStatusColor()}22`,
              color: getStatusColor(),
              padding: '2px 10px',
              borderRadius: '12px',
              border: `1px solid ${getStatusColor()}44`,
            }}>
              {getStatusLabel()}
            </span>
          </div>
          <div style={{
            fontSize: '13px',
            color: '#94a3b8',
            marginTop: '2px',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            whiteSpace: 'nowrap',
            maxWidth: '500px',
          }}>
            &quot;{query}&quot;
          </div>
        </div>
      </div>

      {/* Progress Bar */}
      <div style={{
        background: 'rgba(30, 41, 59, 0.8)',
        borderRadius: '8px',
        height: '6px',
        marginBottom: '16px',
        overflow: 'hidden',
      }}>
        <div style={{
          height: '100%',
          borderRadius: '8px',
          background: `linear-gradient(90deg, ${getStatusColor()}, ${getStatusColor()}cc)`,
          width: `${progress}%`,
          transition: 'width 0.5s ease',
          boxShadow: `0 0 8px ${getStatusColor()}66`,
        }} />
      </div>

      {/* Stats */}
      <div style={{
        display: 'flex',
        gap: '24px',
        marginBottom: '16px',
        padding: '12px 16px',
        background: 'rgba(30, 41, 59, 0.5)',
        borderRadius: '10px',
        border: '1px solid rgba(148, 163, 184, 0.08)',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <Globe size={16} color="#60a5fa" />
          <span style={{ fontSize: '13px', color: '#94a3b8' }}>Sources:</span>
          <span style={{ fontSize: '15px', fontWeight: 600, color: '#e2e8f0' }}>{sourceCount}</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <FileText size={16} color="#34d399" />
          <span style={{ fontSize: '13px', color: '#94a3b8' }}>Findings:</span>
          <span style={{ fontSize: '15px', fontWeight: 600, color: '#e2e8f0' }}>{findingsCount}</span>
        </div>
        {steps.length > 0 && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <Search size={16} color="#a78bfa" />
            <span style={{ fontSize: '13px', color: '#94a3b8' }}>Steps:</span>
            <span style={{ fontSize: '15px', fontWeight: 600, color: '#e2e8f0' }}>
              {steps.filter(s => s.status === 'completed').length}/{steps.length}
            </span>
          </div>
        )}
      </div>

      {/* Research Steps */}
      {steps.length > 0 && (
        <div style={{
          marginBottom: '16px',
          background: 'rgba(30, 41, 59, 0.4)',
          borderRadius: '10px',
          border: '1px solid rgba(148, 163, 184, 0.08)',
          overflow: 'hidden',
        }}>
          <button
            onClick={() => setShowSteps(!showSteps)}
            style={{
              width: '100%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              padding: '10px 16px',
              background: 'none',
              border: 'none',
              color: '#94a3b8',
              cursor: 'pointer',
              fontSize: '13px',
              fontWeight: 500,
            }}
          >
            <span>Research Steps</span>
            {showSteps ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
          </button>
          {showSteps && (
            <div style={{ padding: '0 16px 12px' }}>
              {steps.map(step => (
                <div
                  key={step.index}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '10px',
                    padding: '6px 0',
                    fontSize: '13px',
                    color: step.status === 'completed' ? '#34d399'
                      : step.status === 'running' ? '#60a5fa'
                      : '#64748b',
                  }}
                >
                  {getStepIcon(step.status)}
                  <span style={{
                    fontWeight: step.status === 'running' ? 600 : 400,
                  }}>
                    Step {step.index + 1}: {step.title}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Thinking */}
      {thinking && isActive && (
        <div style={{
          marginBottom: '16px',
          padding: '12px 16px',
          background: 'rgba(167, 139, 250, 0.08)',
          borderRadius: '10px',
          border: '1px solid rgba(167, 139, 250, 0.15)',
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            marginBottom: '6px',
          }}>
            <Brain size={14} color="#a78bfa" />
            <span style={{ fontSize: '12px', fontWeight: 600, color: '#a78bfa' }}>Thinking</span>
          </div>
          <div style={{
            fontSize: '12px',
            color: '#c4b5fd',
            lineHeight: '1.5',
            fontStyle: 'italic',
          }}>
            {thinking.length > 200 ? thinking.slice(0, 200) + '...' : thinking}
          </div>
        </div>
      )}

      {/* Activity Feed */}
      <div
        ref={activityRef}
        style={{
          maxHeight: '180px',
          overflowY: 'auto',
          marginBottom: '16px',
          padding: '12px',
          background: 'rgba(15, 23, 42, 0.6)',
          borderRadius: '10px',
          border: '1px solid rgba(148, 163, 184, 0.08)',
        }}
      >
        {activityLog.length === 0 ? (
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            color: '#64748b',
            fontSize: '13px',
          }}>
            <Loader2 size={14} className="animate-spin" />
            Initializing deep research...
          </div>
        ) : (
          activityLog.map((item, i) => (
            <div
              key={i}
              style={{
                padding: '4px 0',
                fontSize: '12px',
                color: '#94a3b8',
                lineHeight: '1.5',
                display: 'flex',
                justifyContent: 'space-between',
                gap: '12px',
              }}
            >
              <span style={{ flex: 1 }}>{item.text}</span>
              <span style={{ fontSize: '11px', color: '#475569', whiteSpace: 'nowrap' }}>{item.time}</span>
            </div>
          ))
        )}
      </div>

      {/* Error */}
      {error && (
        <div style={{
          marginBottom: '16px',
          padding: '12px 16px',
          background: 'rgba(248, 113, 113, 0.1)',
          borderRadius: '10px',
          border: '1px solid rgba(248, 113, 113, 0.2)',
          display: 'flex',
          alignItems: 'center',
          gap: '10px',
        }}>
          <AlertCircle size={16} color="#f87171" />
          <span style={{ fontSize: '13px', color: '#fca5a5' }}>{error}</span>
        </div>
      )}

      {/* Stop Button */}
      {isActive && (
        <div style={{ display: 'flex', justifyContent: 'center' }}>
          <button
            onClick={handleStop}
            disabled={isStopped}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '8px',
              padding: '10px 24px',
              background: isStopped
                ? 'rgba(148, 163, 184, 0.1)'
                : 'rgba(239, 68, 68, 0.12)',
              border: `1px solid ${isStopped ? 'rgba(148, 163, 184, 0.2)' : 'rgba(239, 68, 68, 0.3)'}`,
              borderRadius: '10px',
              color: isStopped ? '#94a3b8' : '#fca5a5',
              cursor: isStopped ? 'not-allowed' : 'pointer',
              fontSize: '13px',
              fontWeight: 500,
              transition: 'all 0.2s',
            }}
          >
            <Square size={14} />
            {isStopped ? 'Stopping...' : 'Stop Research'}
          </button>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import dynamic from 'next/dynamic';

const ForceGraph2D = dynamic(() => import('react-force-graph-2d'), { ssr: false });

import {
  ZoomIn, ZoomOut, Maximize2, RefreshCw, Database, Search,
  Download, X, ChevronDown, ChevronUp, Eye, EyeOff, Info,
} from 'lucide-react';
import { api } from '@/lib/api';

// ─────────────────────────────────────────────────
// Constants
// ─────────────────────────────────────────────────

const SOURCE_PALETTE = [
  '#60a5fa', '#f87171', '#34d399', '#c084fc', '#fb923c',
  '#22d3ee', '#facc15', '#f472b6', '#a3e635', '#818cf8',
  '#2dd4bf', '#e879f9',
];

// ─────────────────────────────────────────────────
// Types
// ─────────────────────────────────────────────────

interface GraphVisualizerProps {
  onClose?: () => void;
  isFullscreen?: boolean;
}

// ─────────────────────────────────────────────────
// Component
// ─────────────────────────────────────────────────

export function GraphVisualizer({ onClose, isFullscreen = false }: GraphVisualizerProps) {
  // === Core State ===
  const [rawData, setRawData] = useState<{ nodes: any[]; links: any[] }>({ nodes: [], links: [] });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // === Feature State ===
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedNode, setSelectedNode] = useState<any | null>(null);
  const [hoveredNode, setHoveredNode] = useState<any | null>(null);
  const [activeSources, setActiveSources] = useState<Set<string>>(new Set());
  const [activeEdgeTypes, setActiveEdgeTypes] = useState<Set<string>>(new Set());
  const [showPanel, setShowPanel] = useState(true);
  const [showEdgeFilters, setShowEdgeFilters] = useState(false);

  // === Refs ===
  const graphRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);

  // ─── Resize Observer ───────────────────────────
  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver(entries => {
      const { width, height } = entries[0].contentRect;
      setDimensions({ width, height });
    });
    observer.observe(containerRef.current);
    const rect = containerRef.current.getBoundingClientRect();
    setDimensions({ width: rect.width, height: rect.height });
    return () => observer.disconnect();
  }, []);

  // ─── Fetch Graph (no limits) ───────────────────
  const fetchGraph = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await api.getGraphData();
      setRawData(data);
    } catch (err) {
      console.error('Failed to load graph:', err);
      setError('Failed to load knowledge graph data.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchGraph(); }, [fetchGraph]);

  // ─── Initialise filters when data loads ────────
  useEffect(() => {
    if (rawData.nodes.length === 0) return;
    setActiveSources(new Set(rawData.nodes.map((n: any) => n.source || 'unknown')));
    setActiveEdgeTypes(new Set(rawData.links.map((l: any) => l.label || 'unknown')));
  }, [rawData]);

  // ─── Derived: colour map ───────────────────────
  const sourceColorMap = useMemo(() => {
    const sources = [...new Set(rawData.nodes.map((n: any) => n.source || 'unknown'))];
    const map: Record<string, string> = {};
    sources.forEach((s, i) => { map[s] = SOURCE_PALETTE[i % SOURCE_PALETTE.length]; });
    return map;
  }, [rawData.nodes]);

  // ─── Derived: all edge types ───────────────────
  const allEdgeTypes = useMemo(
    () => [...new Set(rawData.links.map((l: any) => l.label || 'unknown'))],
    [rawData.links],
  );

  // ─── Derived: filtered graph data ──────────────
  const filteredData = useMemo(() => {
    const nodes = rawData.nodes.filter((n: any) => activeSources.has(n.source || 'unknown'));
    const nodeIdSet = new Set(nodes.map((n: any) => n.id));
    const links = rawData.links.filter((l: any) =>
      activeEdgeTypes.has(l.label || 'unknown') &&
      nodeIdSet.has(l.source) &&
      nodeIdSet.has(l.target),
    );
    return { nodes, links };
  }, [rawData, activeSources, activeEdgeTypes]);

  const isLargeGraph = filteredData.links.length > 5000;

  // ─── Derived: node degree map ──────────────────
  const nodeDegreeMap = useMemo(() => {
    const deg: Record<string, number> = {};
    filteredData.links.forEach((l: any) => {
      const s = typeof l.source === 'object' ? l.source.id : l.source;
      const t = typeof l.target === 'object' ? l.target.id : l.target;
      deg[s] = (deg[s] || 0) + 1;
      deg[t] = (deg[t] || 0) + 1;
    });
    return deg;
  }, [filteredData.links]);

  // ─── Derived: search matches ───────────────────
  const searchMatches = useMemo(() => {
    if (!searchQuery.trim()) return new Set<string>();
    const q = searchQuery.toLowerCase();
    return new Set(
      filteredData.nodes
        .filter((n: any) =>
          (n.name || '').toLowerCase().includes(q) ||
          (n.label || '').toLowerCase().includes(q),
        )
        .map((n: any) => n.id),
    );
  }, [searchQuery, filteredData.nodes]);

  // ─── Derived: hover neighbourhood ──────────────
  const { highlightNodes, highlightLinks } = useMemo(() => {
    const hNodes = new Set<string>();
    const hLinks = new Set<string>();
    if (!hoveredNode) return { highlightNodes: hNodes, highlightLinks: hLinks };

    hNodes.add(hoveredNode.id);
    filteredData.links.forEach((l: any) => {
      const s = typeof l.source === 'object' ? l.source.id : l.source;
      const t = typeof l.target === 'object' ? l.target.id : l.target;
      if (s === hoveredNode.id || t === hoveredNode.id) {
        hNodes.add(s);
        hNodes.add(t);
        hLinks.add(l.id);
      }
    });
    return { highlightNodes: hNodes, highlightLinks: hLinks };
  }, [hoveredNode, filteredData.links]);

  // ─── Derived: selected node connections ────────
  const selectedConnections = useMemo(() => {
    if (!selectedNode) return [];
    const conns: Array<{ node: any; edgeType: string; weight: number }> = [];
    filteredData.links.forEach((l: any) => {
      const s = typeof l.source === 'object' ? l.source.id : l.source;
      const t = typeof l.target === 'object' ? l.target.id : l.target;
      if (s !== selectedNode.id && t !== selectedNode.id) return;
      const otherId = s === selectedNode.id ? t : s;
      const otherNode = filteredData.nodes.find((n: any) => n.id === otherId);
      if (otherNode) conns.push({ node: otherNode, edgeType: l.label, weight: l.weight || 0 });
    });
    return conns.sort((a, b) => b.weight - a.weight).slice(0, 25);
  }, [selectedNode, filteredData]);

  // ─── Handlers ──────────────────────────────────

  const handleZoomIn = useCallback(() => {
    graphRef.current?.zoom(graphRef.current.zoom() * 1.5, 400);
  }, []);

  const handleZoomOut = useCallback(() => {
    graphRef.current?.zoom(graphRef.current.zoom() / 1.5, 400);
  }, []);

  const handleCenter = useCallback(() => {
    graphRef.current?.zoomToFit(400, 50);
  }, []);

  const handleExportPNG = useCallback(() => {
    const canvas = containerRef.current?.querySelector('canvas');
    if (!canvas) return;
    const a = document.createElement('a');
    a.download = 'knowledge-graph.png';
    a.href = canvas.toDataURL('image/png');
    a.click();
  }, []);

  const toggleSource = useCallback((source: string) => {
    setActiveSources(prev => {
      const next = new Set(prev);
      if (next.has(source)) next.delete(source); else next.add(source);
      return next;
    });
  }, []);

  const toggleEdgeType = useCallback((et: string) => {
    setActiveEdgeTypes(prev => {
      const next = new Set(prev);
      if (next.has(et)) next.delete(et); else next.add(et);
      return next;
    });
  }, []);

  const handleNodeClick = useCallback((node: any) => {
    setSelectedNode(node);
    graphRef.current?.centerAt(node.x, node.y, 500);
    graphRef.current?.zoom(3, 500);
  }, []);

  const handleNodeHover = useCallback((node: any | null) => {
    setHoveredNode(node || null);
  }, []);

  const focusSearchResult = useCallback(() => {
    if (searchMatches.size === 0) return;
    const firstId = [...searchMatches][0];
    const node = filteredData.nodes.find((n: any) => n.id === firstId);
    if (node?.x !== undefined) {
      graphRef.current?.centerAt(node.x, node.y, 500);
      graphRef.current?.zoom(3, 500);
    }
  }, [searchMatches, filteredData.nodes]);

  // ─── Node sizing ───────────────────────────────
  const getNodeSize = useCallback((node: any) => {
    const degree = nodeDegreeMap[node.id] || 0;
    return Math.max(3, Math.min(14, 3 + Math.sqrt(degree) * 1.2));
  }, [nodeDegreeMap]);

  const avgDegree = filteredData.nodes.length > 0
    ? ((2 * filteredData.links.length) / filteredData.nodes.length).toFixed(1)
    : '0';

  // ─────────────────────────────────────────────────
  // Render
  // ─────────────────────────────────────────────────

  return (
    <div
      ref={containerRef}
      className="relative w-full h-full flex bg-[#0a0a0a] overflow-hidden rounded-xl border border-white/10"
    >
      {/* ═══════════ LEFT PANEL ═══════════ */}
      {showPanel && (
        <div
          className="absolute top-4 left-4 z-10 w-[220px] bg-black/70 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden"
          style={{ maxHeight: 'calc(100% - 32px)' }}
        >
          {/* Stats */}
          <div className="p-3 border-b border-white/10">
            <div className="flex items-center gap-2 mb-2">
              <Database className="w-4 h-4 text-emerald-400" />
              <span className="text-xs font-bold tracking-widest uppercase text-white">
                Knowledge Graph
              </span>
            </div>
            <div className="grid grid-cols-3 gap-1 text-center">
              <div>
                <div className="text-[10px] text-neutral-500 font-bold uppercase">Nodes</div>
                <div className="text-sm font-black text-emerald-400">
                  {filteredData.nodes.length}
                </div>
              </div>
              <div>
                <div className="text-[10px] text-neutral-500 font-bold uppercase">Edges</div>
                <div className="text-sm font-black text-blue-400">
                  {filteredData.links.length.toLocaleString()}
                </div>
              </div>
              <div>
                <div className="text-[10px] text-neutral-500 font-bold uppercase">Avg Deg</div>
                <div className="text-sm font-black text-purple-400">{avgDegree}</div>
              </div>
            </div>
          </div>

          {/* Search */}
          <div className="p-2 border-b border-white/10">
            <div className="relative">
              <Search className="absolute left-2 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-neutral-500" />
              <input
                ref={searchInputRef}
                type="text"
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') focusSearchResult(); }}
                placeholder="Search nodes..."
                className="w-full bg-white/5 border border-white/10 rounded-lg pl-8 pr-8 py-1.5 text-xs text-white placeholder-neutral-600 focus:outline-none focus:border-emerald-500/50"
              />
              {searchQuery && (
                <button
                  onClick={() => setSearchQuery('')}
                  className="absolute right-2 top-1/2 -translate-y-1/2"
                >
                  <X className="w-3 h-3 text-neutral-500 hover:text-white" />
                </button>
              )}
            </div>
            {searchQuery && (
              <div className="text-[10px] text-neutral-500 mt-1 px-1">
                {searchMatches.size} match{searchMatches.size !== 1 ? 'es' : ''} — Enter to
                focus
              </div>
            )}
          </div>

          {/* Scrollable filter area */}
          <div className="flex-1 overflow-y-auto">
            {/* Source Filters */}
            <div className="p-2 border-b border-white/10">
              <div className="flex items-center justify-between mb-1">
                <span className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest">
                  Sources
                </span>
                <div className="flex gap-1">
                  <button
                    onClick={() => setActiveSources(new Set(Object.keys(sourceColorMap)))}
                    className="text-[9px] text-neutral-500 hover:text-emerald-400 px-1"
                  >
                    All
                  </button>
                  <button
                    onClick={() => setActiveSources(new Set())}
                    className="text-[9px] text-neutral-500 hover:text-red-400 px-1"
                  >
                    None
                  </button>
                </div>
              </div>
              {Object.entries(sourceColorMap).map(([src, color]) => {
                const active = activeSources.has(src);
                return (
                  <button
                    key={src}
                    onClick={() => toggleSource(src)}
                    className="flex items-center gap-2 w-full px-1.5 py-1 rounded-md hover:bg-white/5 transition-colors"
                    title={src}
                  >
                    <div
                      className="w-2.5 h-2.5 rounded-full flex-shrink-0 transition-opacity"
                      style={{
                        background: color,
                        boxShadow: active ? `0 0 6px ${color}66` : 'none',
                        opacity: active ? 1 : 0.2,
                      }}
                    />
                    <span
                      className={`text-[11px] truncate transition-opacity ${
                        active ? 'text-neutral-300' : 'text-neutral-600 line-through'
                      }`}
                    >
                      {src.length > 24 ? src.slice(0, 22) + '...' : src}
                    </span>
                  </button>
                );
              })}
            </div>

            {/* Edge Type Filters */}
            <div className="p-2">
              <button
                onClick={() => setShowEdgeFilters(v => !v)}
                className="flex items-center justify-between w-full mb-1"
              >
                <span className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest">
                  Edge Types
                </span>
                {showEdgeFilters ? (
                  <ChevronUp className="w-3 h-3 text-neutral-500" />
                ) : (
                  <ChevronDown className="w-3 h-3 text-neutral-500" />
                )}
              </button>

              {showEdgeFilters && (
                <>
                  <div className="flex gap-1 mb-1">
                    <button
                      onClick={() => setActiveEdgeTypes(new Set(allEdgeTypes))}
                      className="text-[9px] text-neutral-500 hover:text-emerald-400 px-1"
                    >
                      All
                    </button>
                    <button
                      onClick={() => setActiveEdgeTypes(new Set())}
                      className="text-[9px] text-neutral-500 hover:text-red-400 px-1"
                    >
                      None
                    </button>
                  </div>
                  {allEdgeTypes.map(et => {
                    const active = activeEdgeTypes.has(et);
                    return (
                      <button
                        key={et}
                        onClick={() => toggleEdgeType(et)}
                        className="flex items-center gap-2 w-full px-1.5 py-1 rounded-md hover:bg-white/5 transition-colors"
                      >
                        <div
                          className={`w-2 h-2 rounded-sm border transition-colors ${
                            active
                              ? 'bg-blue-500 border-blue-400'
                              : 'bg-transparent border-neutral-600'
                          }`}
                        />
                        <span
                          className={`text-[11px] ${
                            active ? 'text-neutral-300' : 'text-neutral-600 line-through'
                          }`}
                        >
                          {et.replace(/_/g, ' ')}
                        </span>
                      </button>
                    );
                  })}
                </>
              )}
            </div>
          </div>
        </div>
      )}

      {/* ═══════════ RIGHT PANEL: Node Details ═══════════ */}
      {selectedNode && (
        <div
          className="absolute top-4 right-4 z-10 w-[280px] bg-black/80 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden"
          style={{ maxHeight: 'calc(100% - 32px)' }}
        >
          {/* Header */}
          <div className="p-3 border-b border-white/10 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Info className="w-4 h-4 text-blue-400" />
              <span className="text-xs font-bold text-white uppercase tracking-wider">
                Node Details
              </span>
            </div>
            <button
              onClick={() => setSelectedNode(null)}
              className="text-neutral-500 hover:text-white"
            >
              <X className="w-4 h-4" />
            </button>
          </div>

          {/* Body */}
          <div className="flex-1 overflow-y-auto p-3 space-y-3">
            {/* Source */}
            <div>
              <div className="text-[10px] text-neutral-500 uppercase tracking-wider mb-0.5">
                Source
              </div>
              <div className="flex items-center gap-2">
                <div
                  className="w-2.5 h-2.5 rounded-full flex-shrink-0"
                  style={{
                    background:
                      sourceColorMap[selectedNode.source || 'unknown'] || '#94a3b8',
                  }}
                />
                <span
                  className="text-xs text-white font-medium truncate"
                  title={selectedNode.source || selectedNode.name}
                >
                  {(selectedNode.source || selectedNode.name || 'Unknown').slice(0, 40)}
                </span>
              </div>
            </div>

            {/* Content */}
            <div>
              <div className="text-[10px] text-neutral-500 uppercase tracking-wider mb-0.5">
                Content
              </div>
              <div className="text-xs text-neutral-300 leading-relaxed bg-white/5 rounded-lg p-2 max-h-[120px] overflow-y-auto">
                {selectedNode.label || 'No content.'}
              </div>
            </div>

            {/* Meta badges */}
            <div className="flex gap-2">
              <div className="flex-1 bg-white/5 rounded-lg p-2 text-center">
                <div className="text-[9px] text-neutral-500 uppercase">Type</div>
                <div className="text-[11px] text-white font-bold">
                  {selectedNode.group || 'text'}
                </div>
              </div>
              <div className="flex-1 bg-white/5 rounded-lg p-2 text-center">
                <div className="text-[9px] text-neutral-500 uppercase">Resolution</div>
                <div className="text-[11px] text-white font-bold">
                  {selectedNode.resolution || 'unknown'}
                </div>
              </div>
              <div className="flex-1 bg-white/5 rounded-lg p-2 text-center">
                <div className="text-[9px] text-neutral-500 uppercase">Degree</div>
                <div className="text-[11px] text-emerald-400 font-bold">
                  {nodeDegreeMap[selectedNode.id] || 0}
                </div>
              </div>
            </div>

            {/* Connections list */}
            {selectedConnections.length > 0 && (
              <div>
                <div className="text-[10px] text-neutral-500 uppercase tracking-wider mb-1">
                  Top Connections ({selectedConnections.length})
                </div>
                <div className="space-y-0.5">
                  {selectedConnections.map((conn, i) => (
                    <button
                      key={i}
                      onClick={() => {
                        setSelectedNode(conn.node);
                        if (conn.node.x !== undefined)
                          graphRef.current?.centerAt(conn.node.x, conn.node.y, 500);
                      }}
                      className="w-full flex items-center gap-2 px-2 py-1 rounded-md hover:bg-white/10 transition-colors text-left"
                    >
                      <div
                        className="w-2 h-2 rounded-full flex-shrink-0"
                        style={{
                          background:
                            sourceColorMap[conn.node.source || 'unknown'] || '#94a3b8',
                        }}
                      />
                      <div className="flex-1 min-w-0">
                        <div className="text-[10px] text-neutral-400 truncate">
                          {(conn.node.label || conn.node.name || 'Node').slice(0, 40)}
                        </div>
                      </div>
                      <span className="text-[9px] text-neutral-600 flex-shrink-0">
                        {conn.edgeType?.replace(/_/g, ' ')}
                      </span>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ═══════════ BOTTOM CONTROLS ═══════════ */}
      <div className="absolute bottom-4 right-4 z-10 flex items-center gap-1 p-1 bg-black/60 backdrop-blur-md border border-white/10 rounded-xl shadow-2xl">
        <button
          onClick={handleZoomIn}
          className="p-2 hover:bg-white/10 rounded-lg text-neutral-400 hover:text-white transition-colors"
          title="Zoom In"
        >
          <ZoomIn className="w-4 h-4" />
        </button>
        <button
          onClick={handleZoomOut}
          className="p-2 hover:bg-white/10 rounded-lg text-neutral-400 hover:text-white transition-colors"
          title="Zoom Out"
        >
          <ZoomOut className="w-4 h-4" />
        </button>
        <div className="w-px h-4 bg-white/10" />
        <button
          onClick={handleCenter}
          className="p-2 hover:bg-white/10 rounded-lg text-neutral-400 hover:text-white transition-colors"
          title="Fit to View"
        >
          <Maximize2 className="w-4 h-4" />
        </button>
        <div className="w-px h-4 bg-white/10" />
        <button
          onClick={handleExportPNG}
          className="p-2 hover:bg-white/10 rounded-lg text-neutral-400 hover:text-white transition-colors"
          title="Export as PNG"
        >
          <Download className="w-4 h-4" />
        </button>
        <div className="w-px h-4 bg-white/10" />
        <button
          onClick={() => setShowPanel(p => !p)}
          className="p-2 hover:bg-white/10 rounded-lg text-neutral-400 hover:text-white transition-colors"
          title={showPanel ? 'Hide Panel' : 'Show Panel'}
        >
          {showPanel ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
        </button>
        <div className="w-px h-4 bg-white/10" />
        <button
          onClick={fetchGraph}
          className="p-2 hover:bg-white/10 rounded-lg text-neutral-400 hover:text-white transition-colors"
          title="Reload Graph"
        >
          <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {/* ═══════════ LOADING ═══════════ */}
      {loading && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-black/40 backdrop-blur-xl">
          <RefreshCw className="w-8 h-8 text-neutral-400 animate-spin mb-4" />
          <p className="text-sm font-bold tracking-widest uppercase text-neutral-400 animate-pulse">
            Computing Force Physics Engine...
          </p>
        </div>
      )}

      {/* ═══════════ ERROR ═══════════ */}
      {error && !loading && (
        <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-[#0a0a0a]">
          <p className="text-red-400 text-sm">{error}</p>
          <button
            onClick={fetchGraph}
            className="mt-4 px-4 py-2 bg-white/5 hover:bg-white/10 rounded-lg text-sm text-white transition-colors border border-white/10"
          >
            Try Again
          </button>
        </div>
      )}

      {/* ═══════════ GRAPH CANVAS ═══════════ */}
      <div className="flex-1 w-full h-full cursor-grab active:cursor-grabbing">
        {!loading && !error && dimensions.width > 0 && dimensions.height > 0 && (
          <ForceGraph2D
            ref={graphRef}
            width={dimensions.width}
            height={dimensions.height}
            graphData={filteredData}
            /* ── Performance tuning ── */
            cooldownTicks={150}
            warmupTicks={isLargeGraph ? 50 : 0}
            d3AlphaDecay={0.02}
            d3VelocityDecay={0.3}
            /* ── Tooltips ── */
            nodeLabel={(node: any) => `
              <div style="background:rgba(10,10,10,.95);padding:12px;border-radius:8px;border:1px solid rgba(255,255,255,.1);max-width:320px;color:#fff;box-shadow:0 10px 25px rgba(0,0,0,.5)">
                <div style="font-weight:700;font-size:13px;color:${sourceColorMap[node.source || 'unknown'] || '#94a3b8'};margin-bottom:6px;padding-bottom:6px;border-bottom:1px solid rgba(255,255,255,.1);text-transform:uppercase;letter-spacing:.5px">
                  ${node.name || 'Knowledge Node'}
                </div>
                <div style="font-size:13px;line-height:1.5;word-wrap:break-word;white-space:pre-wrap;color:rgba(255,255,255,.85)">
                  ${node.label || 'No content available.'}
                </div>
              </div>
            `}
            linkLabel={(link: any) =>
              `<div style="background:rgba(10,10,10,.95);padding:8px;border-radius:6px;border:1px solid rgba(255,255,255,.1);color:#fff;font-size:12px;font-weight:bold;text-transform:uppercase">${link.label || 'Connected'}</div>`
            }
            /* ── Link styling ── */
            linkColor={(link: any) => {
              if (hoveredNode && highlightLinks.size > 0)
                return highlightLinks.has(link.id)
                  ? 'rgba(255,255,255,0.4)'
                  : 'rgba(255,255,255,0.02)';
              return 'rgba(255,255,255,0.08)';
            }}
            linkWidth={(link: any) =>
              hoveredNode && highlightLinks.has(link.id) ? 2 : 0.5
            }
            linkDirectionalParticles={isLargeGraph ? 0 : 1}
            linkDirectionalParticleSpeed={0.004}
            linkCanvasObjectMode={isLargeGraph ? undefined : (() => 'after' as const)}
            linkCanvasObject={
              isLargeGraph
                ? undefined
                : (link: any, ctx: CanvasRenderingContext2D, globalScale: number) => {
                    if (globalScale < 3.5 || !link.label) return;
                    const start = link.source;
                    const end = link.target;
                    if (typeof start !== 'object' || typeof end !== 'object') return;
                    const mx = (start.x + end.x) / 2;
                    const my = (start.y + end.y) / 2;
                    const angle = Math.atan2(end.y - start.y, end.x - start.x);
                    ctx.save();
                    ctx.translate(mx, my);
                    ctx.rotate(angle);
                    const fs = 10 / globalScale;
                    ctx.font = `bold ${fs}px Inter,sans-serif`;
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';
                    const tw = ctx.measureText(link.label).width;
                    ctx.fillStyle = 'rgba(0,0,0,0.6)';
                    ctx.fillRect(
                      -tw / 2 - 2 / globalScale,
                      -fs / 2 - 2 / globalScale,
                      tw + 4 / globalScale,
                      fs + 4 / globalScale,
                    );
                    ctx.fillStyle = 'rgba(255,255,255,0.7)';
                    ctx.fillText(link.label, 0, 0);
                    ctx.restore();
                  }
            }
            /* ── Node rendering ── */
            nodeCanvasObject={(
              node: any,
              ctx: CanvasRenderingContext2D,
              globalScale: number,
            ) => {
              const nodeId = node.id;
              const size = getNodeSize(node);
              const color =
                sourceColorMap[node.source || 'unknown'] || '#94a3b8';

              // Decide opacity — dim non-matches during search or hover
              let opacity = 1;
              const isSearchActive =
                searchQuery.trim() !== '' && searchMatches.size > 0;
              const isHoverActive =
                hoveredNode !== null && highlightNodes.size > 0;

              if (isSearchActive && !searchMatches.has(nodeId)) opacity = 0.06;
              else if (isHoverActive && !highlightNodes.has(nodeId)) opacity = 0.06;

              // Glow ring for highlighted / searched nodes
              const isHighlighted =
                (isSearchActive && searchMatches.has(nodeId)) ||
                (isHoverActive && highlightNodes.has(nodeId));
              if (isHighlighted) {
                ctx.beginPath();
                ctx.arc(node.x!, node.y!, size + 4, 0, 2 * Math.PI);
                ctx.fillStyle = color + '33';
                ctx.fill();
              }

              // Main circle
              ctx.globalAlpha = opacity;
              ctx.beginPath();
              ctx.arc(node.x!, node.y!, size, 0, 2 * Math.PI);
              ctx.fillStyle = color;
              ctx.fill();

              // Text label when zoomed in
              if (globalScale > 2) {
                const label = (node.name || 'Node') as string;
                const fs = Math.max(10 / globalScale, 1.5);
                ctx.font = `${fs}px Inter,sans-serif`;
                ctx.textAlign = 'center';
                ctx.textBaseline = 'top';
                const tw = ctx.measureText(label).width;
                const pad = 2 / globalScale;
                ctx.fillStyle = 'rgba(0,0,0,0.8)';
                ctx.fillRect(
                  node.x! - tw / 2 - pad,
                  node.y! + size + pad,
                  tw + pad * 2,
                  fs + pad * 2,
                );
                ctx.fillStyle = 'rgba(255,255,255,0.9)';
                ctx.fillText(label, node.x!, node.y! + size + pad * 2);
              }

              ctx.globalAlpha = 1;
            }}
            nodeRelSize={6}
            /* ── Interactions ── */
            onNodeClick={handleNodeClick}
            onNodeHover={handleNodeHover}
            onBackgroundClick={() => setSelectedNode(null)}
            onEngineStop={() => graphRef.current?.zoomToFit(400, 50)}
          />
        )}
      </div>
    </div>
  );
}

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, CheckCircle, AlertCircle, Info, HelpCircle } from 'lucide-react';
import { cn } from '@/lib/utils';

export type NotificationType = 'success' | 'error' | 'info' | 'confirm';

interface NotificationModalProps {
  isOpen: boolean;
  type: NotificationType;
  title: string;
  message: string;
  onClose: () => void;
  onConfirm?: () => void;
  confirmText?: string;
  cancelText?: string;
}

export function NotificationModal({
  isOpen,
  type,
  title,
  message,
  onClose,
  onConfirm,
  confirmText = 'Confirm',
  cancelText = 'Cancel'
}: NotificationModalProps) {
  if (!isOpen) return null;

  const icons = {
    success: <CheckCircle className="w-6 h-6 text-green-400" />,
    error: <AlertCircle className="w-6 h-6 text-red-400" />,
    info: <Info className="w-6 h-6 text-blue-400" />,
    confirm: <HelpCircle className="w-6 h-6 text-primary" />
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 10 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 10 }}
        className="w-full max-w-md bg-[#0a0a0a] border border-white/10 rounded-2xl shadow-2xl overflow-hidden"
      >
        <div className="p-6 space-y-4">
          <div className="flex items-center gap-3">
            <div className={cn(
              "p-2 rounded-xl bg-white/5",
              type === 'success' && "bg-green-500/10",
              type === 'error' && "bg-red-500/10",
              type === 'info' && "bg-blue-500/10",
              type === 'confirm' && "bg-primary/10"
            )}>
              {icons[type]}
            </div>
            <h3 className="text-lg font-semibold text-white">{title}</h3>
          </div>
          
          <p className="text-neutral-400 text-sm leading-relaxed">
            {message}
          </p>

          <div className="flex items-center justify-end gap-3 pt-4">
            {type === 'confirm' ? (
              <>
                <button
                  onClick={onClose}
                  className="px-4 py-2 rounded-xl text-sm font-medium text-neutral-400 hover:text-white hover:bg-white/5 transition-colors"
                >
                  {cancelText}
                </button>
                <button
                  onClick={() => {
                    onConfirm?.();
                    onClose();
                  }}
                  className="px-4 py-2 rounded-xl text-sm font-medium bg-primary hover:bg-primary-hover text-white transition-all shadow-[0_0_15px_rgba(147,51,234,0.3)]"
                >
                  {confirmText}
                </button>
              </>
            ) : (
              <button
                onClick={onClose}
                className="px-6 py-2 rounded-xl text-sm font-medium bg-white/5 hover:bg-white/10 text-white border border-white/10 transition-colors"
              >
                Close
              </button>
            )}
          </div>
        </div>
      </motion.div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
// Native confirm/alert replaced with custom NotificationModal
import { X, Database, Trash2, RefreshCw, FileText, Music, Video, Table, Link as LinkIcon, Image, FileJson } from 'lucide-react';
import { api, Stats, CostAnalytics } from '@/lib/api';
import { cn } from '@/lib/utils';
import { motion } from 'framer-motion';
import { useNotification } from '@/context/NotificationContext';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
}

import { GraphVisualizer } from './GraphVisualizer';
import CostDashboard from './CostDashboard';

type CostPeriod = 'weekly' | 'monthly' | 'quarterly' | 'yearly';

export function SettingsModal({ isOpen, onClose }: SettingsModalProps) {
  const [sources, setSources] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [stats, setStats] = useState<Stats | null>(null);
  const [showGraph, setShowGraph] = useState(false);
  const [costLoading, setCostLoading] = useState(false);
  const [costPeriod, setCostPeriod] = useState<CostPeriod>('weekly');
  const [costAnalytics, setCostAnalytics] = useState<CostAnalytics | null>(null);

  // ... (keep fetchData etc)
  const fetchData = async () => {
    try {
      setLoading(true);
      const [sourcesData, statsData] = await Promise.all([
        api.listSources(),
        api.getStats()
      ]);
      setSources(sourcesData || []);
      setStats(statsData);
    } catch (e) {
      console.error('Failed to fetch data', e);
      try {
        const sourcesData = await api.listSources();
        setSources(sourcesData || []);
      } catch (innerE) {
        console.error('Failed to fetch sources too', innerE);
      }
    } finally {
      setLoading(false);
    }
  };

  const fetchCostAnalytics = async (period: string) => {
    setCostLoading(true);
    try {
      const data = await api.getCostAnalytics(period);
      setCostAnalytics(data || null);
    } catch (e) {
      console.error('Failed to fetch cost analytics', e);
      setCostAnalytics(null);
    } finally {
      setCostLoading(false);
    }
  };

  useEffect(() => {
    if (isOpen) {
      fetchData();
      setShowGraph(false);
    }
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) return;
    if (showGraph) return;
    fetchCostAnalytics(costPeriod);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [costPeriod, showGraph, isOpen]);

  const { showNotification } = useNotification();

  const handleDeleteSource = async (name: string) => {
    showNotification({
      type: 'confirm',
      title: 'Delete Source',
      message: `Are you sure you want to delete "${name}" and all its associated data? This action cannot be undone.`,
      confirmText: 'Delete',
      onConfirm: async () => {
        try {
          await api.deleteSource(name);
          showNotification({
            type: 'success',
            title: 'Source Deleted',
            message: `"${name}" has been successfully removed from the knowledge base.`
          });
          fetchData();
        } catch (err) {
          console.error('Failed to delete source', err);
          showNotification({
            type: 'error',
            title: 'Deletion Failed',
            message: `Could not delete "${name}". Please check the system logs.`
          });
        }
      }
    });
  };

  const getFileIcon = (name: string) => {
    const ext = name.split('.').pop()?.toLowerCase();
    if (['jpg', 'jpeg', 'png', 'gif', 'webp'].includes(ext || '')) return <Image className="w-4 h-4 text-blue-400" />;
    if (['mp3', 'wav', 'm4a', 'ogg'].includes(ext || '')) return <Music className="w-4 h-4 text-green-400" />;
    if (['mp4', 'avi', 'mov', 'mkv'].includes(ext || '')) return <Video className="w-4 h-4 text-red-400" />;
    if (['csv', 'tsv', 'xlsx', 'xls'].includes(ext || '')) return <Table className="w-4 h-4 text-yellow-400" />;
    if (['json'].includes(ext || '')) return <FileJson className="w-4 h-4 text-orange-400" />;
    if (name.startsWith('http')) return <LinkIcon className="w-4 h-4 text-purple-400" />;
    return <FileText className="w-4 h-4 text-neutral-400" />;
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <motion.div 
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95 }}
        className={cn(
          "w-full bg-[#0a0a0a] border border-white/10 rounded-2xl shadow-2xl overflow-hidden flex flex-col transition-all duration-500",
          showGraph ? "max-w-6xl h-[85vh]" : "max-w-3xl max-h-[90vh]"
        )}
      >
        <div className="p-4 border-b border-white/10 flex justify-between items-center bg-white/5 shrink-0">
          <h2 className="font-semibold flex items-center gap-2 text-white">
            <Database className="w-4 h-4 text-primary" />
            {showGraph ? "Knowledge Graph Visualization" : "Knowledge Base & Settings"}
          </h2>
          <div className="flex items-center gap-4">
            {showGraph && (
              <button 
                onClick={() => setShowGraph(false)}
                className="text-xs px-3 py-1.5 bg-white/10 hover:bg-white/20 rounded-lg transition-colors font-bold text-white tracking-widest uppercase"
              >
                Back to Settings
              </button>
            )}
            {!showGraph && (
              <button onClick={fetchData} className="text-neutral-400 hover:text-white transition-colors">
                <RefreshCw className={cn("w-4 h-4", loading && "animate-spin")} />
              </button>
            )}
            <button onClick={onClose} className="p-1 hover:bg-white/10 rounded-lg transition-colors text-neutral-400">
              <X className="w-4 h-4" />
            </button>
          </div>
        </div>

        {showGraph ? (
          <div className="flex-1 w-full h-full p-4 relative bg-black/40">
            <GraphVisualizer />
          </div>
        ) : (
          <div className="flex-1 overflow-y-auto p-6 space-y-8">
            {/* Stats section */}
            {stats && (
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="bg-white/5 border border-white/5 p-4 rounded-xl">
                   <p className="text-[10px] uppercase tracking-wider text-neutral-500 font-bold mb-1">Total Atoms</p>
                   <p className="text-2xl font-bold text-white">{stats.database.total_nodes}</p>
                </div>
                <div className="bg-white/5 border border-white/5 p-4 rounded-xl">
                   <p className="text-[10px] uppercase tracking-wider text-neutral-500 font-bold mb-1">Total Edges</p>
                   <p className="text-2xl font-bold text-white">{stats.database.total_edges}</p>
                </div>
                
                <div 
                  onClick={() => setShowGraph(true)}
                  className="col-span-2 bg-emerald-500/10 hover:bg-emerald-500/20 border border-emerald-500/30 p-4 rounded-xl cursor-pointer transition-colors flex items-center justify-between group"
                >
                  <div>
                    <p className="text-[10px] uppercase tracking-wider text-emerald-400/70 font-bold mb-1">Interactive Feature</p>
                    <p className="text-lg font-bold text-emerald-400 group-hover:text-emerald-300">Visualize Knowledge Graph</p>
                  </div>
                  <Database className="w-8 h-8 text-emerald-500/50 group-hover:text-emerald-400 transition-colors" />
                </div>
              </div>
            )}

            {/* LLM Cost & Token Analytics */}
            <div className="space-y-4">
              <div className="flex items-center justify-between gap-4 flex-wrap">
                <div>
                  <h3 className="text-sm font-medium text-white/70">LLM Cost & Token Analytics</h3>
                  <p className="text-[10px] uppercase tracking-widest text-neutral-500 font-bold mt-1">
                    Tokens are estimated; cost uses best-effort pricing
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  <span className="text-[10px] uppercase tracking-widest text-neutral-500 font-bold">Period</span>
                  <select
                    value={costPeriod}
                    onChange={(e) => setCostPeriod(e.target.value as CostPeriod)}
                    className="bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-xs text-neutral-200 outline-none"
                  >
                    <option value="weekly">Weekly</option>
                    <option value="monthly">Monthly</option>
                    <option value="quarterly">Quarterly</option>
                    <option value="yearly">Yearly</option>
                  </select>
                </div>
              </div>

              {costLoading ? (
                <div className="text-xs text-neutral-500">Loading analytics...</div>
              ) : (
                <CostDashboard data={costAnalytics} />
              )}
            </div>

            <div className="space-y-4">
              <h3 className="text-sm font-medium text-white/70">Ingested Media (Documents, Audio, Video, Datasets)</h3>
              <div className="grid gap-2">
                {sources.length === 0 ? (
                  <div className="text-center py-12 bg-white/5 border border-dashed border-white/10 rounded-2xl text-neutral-600 italic text-sm">
                    No media ingested yet.
                  </div>
                ) : (
                  sources.map((source) => (
                    <div key={source} className="flex items-center justify-between p-3 bg-white/5 rounded-xl border border-white/5 group hover:border-white/10 transition-colors">
                      <div className="flex items-center gap-3 overflow-hidden">
                        <div className="w-8 h-8 rounded-lg bg-black/40 flex items-center justify-center shrink-0">
                          {getFileIcon(source)}
                        </div>
                        <span className="text-sm text-neutral-300 truncate" title={source}>{source}</span>
                      </div>
                      <button 
                        onClick={() => handleDeleteSource(source)}
                        className="p-2 text-neutral-600 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        )}
      </motion.div>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Settings, Upload, MessageSquare, Plus, Database, Cpu, Trash2, PanelLeft, Edit2, Check, X, Key } from 'lucide-react';
import { cn } from '@/lib/utils';
import { ChatSession } from '@/lib/api';

interface SidebarProps {
  onOpenSettings: () => void;
  onOpenIngest: () => void;
  onOpenApiKeys: () => void;
  isCollapsed: boolean;
  onToggle: () => void;
  
  // Chat Management
  chats: ChatSession[];
  currentChatId: string | null;
  onSelectChat: (id: string) => void;
  onCreateChat: () => void;
  onDeleteChat: (id: string) => void;
  onRenameChat: (id: string, newTitle: string) => void;
}

export function Sidebar({ 
  onOpenSettings, 
  onOpenIngest, 
  onOpenApiKeys,
  isCollapsed, 
  onToggle,
  chats,
  currentChatId,
  onSelectChat,
  onCreateChat,
  onDeleteChat,
  onRenameChat
}: SidebarProps) {
  
  const [editingChatId, setEditingChatId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState("");
  const editInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (editingChatId && editInputRef.current) {
      editInputRef.current.focus();
    }
  }, [editingChatId]);

  const startEditing = (e: React.MouseEvent, chat: ChatSession) => {
    e.stopPropagation();
    setEditingChatId(chat.id);
    setEditTitle(chat.title);
  };

  const saveEdit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (editingChatId && editTitle.trim()) {
      onRenameChat(editingChatId, editTitle.trim());
      setEditingChatId(null);
    }
  };

  const cancelEdit = (e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingChatId(null);
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    onDeleteChat(id);
  };

  return (
    <div className={cn(
      "h-screen border-r border-white/10 flex flex-col glass backdrop-blur-xl shrink-0 transition-all duration-300 relative z-20",
      isCollapsed ? "w-[70px]" : "w-64"
    )}>
      <div className="p-4 flex items-center justify-between border-b border-white/10 relative">
        <div className={cn("flex items-center gap-2 overflow-hidden transition-all", isCollapsed && "w-full justify-center")}>
          <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center shadow-[0_0_15px_rgba(147,51,234,0.5)] shrink-0">
            <Database className="w-5 h-5 text-white" />
          </div>
          <h1 className={cn("font-bold text-lg tracking-tight transition-opacity duration-200", isCollapsed ? "hidden opacity-0" : "opacity-100")}>
            Albot
          </h1>
        </div>
        
        <button 
          onClick={onToggle}
          className={cn(
            "p-1.5 hover:bg-white/5 rounded-lg transition-all text-neutral-500 hover:text-white z-50",
            isCollapsed 
              ? "absolute -right-3 top-4 bg-[#0a0a0a] border border-white/10 shadow-xl rounded-full" 
              : "relative"
          )}
        >
          <PanelLeft className={cn("w-4 h-4 transition-transform", isCollapsed && "rotate-180")} />
        </button>
      </div>

      <div className="p-3">
        <button 
          onClick={onCreateChat} 
          className={cn(
            "flex items-center gap-2 rounded-xl border border-white/10 hover:bg-white/5 transition-all text-sm font-medium hover:border-primary/50 group bg-primary/5",
            isCollapsed ? "w-full aspect-square justify-center p-0" : "px-4 py-3 w-full"
          )}
          title="New Chat"
        >
          <Plus className="w-5 h-5 text-primary group-hover:text-primary-glow" />
          {!isCollapsed && <span>New Chat</span>}
        </button>
      </div>

      <div className="flex-1 overflow-y-auto px-2 py-2 CustomScrollbar">
        <div className="space-y-4">
          {!isCollapsed && <p className="text-xs font-medium text-neutral-500 uppercase tracking-wider px-2">Recent</p>}
          
          <div className="space-y-1">
            {chats.length === 0 ? (
               <div className="text-center py-4 text-xs text-neutral-600 italic">
                 {isCollapsed ? "..." : "No recent chats"}
               </div>
            ) : (
              chats.map(chat => (
                <div 
                  key={chat.id}
                  onClick={() => onSelectChat(chat.id)}
                  className={cn(
                    "flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm transition-all cursor-pointer group relative",
                    currentChatId === chat.id 
                      ? "bg-white/10 text-white shadow-lg border border-white/5" 
                      : "text-neutral-400 hover:text-white hover:bg-white/5",
                    isCollapsed && "justify-center px-0 py-3"
                  )}
                  title={chat.title}
                >
                  <MessageSquare className={cn(
                    "w-4 h-4 shrink-0 transition-colors", 
                    currentChatId === chat.id ? "text-primary" : "text-neutral-500 group-hover:text-primary/70"
                  )} />
                  
                  {!isCollapsed && (
                    <div className="flex-1 overflow-hidden">
                      {editingChatId === chat.id ? (
                        <form onSubmit={saveEdit} className="flex items-center gap-1" onClick={e => e.stopPropagation()}>
                          <input 
                            ref={editInputRef}
                            type="text" 
                            value={editTitle}
                            onChange={e => setEditTitle(e.target.value)}
                            className="bg-black/50 border border-primary/50 rounded px-1 py-0.5 text-xs w-full focus:outline-none text-white"
                            onBlur={() => setEditingChatId(null)} 
                            onKeyDown={e => {
                                if (e.key === 'Escape') setEditingChatId(null);
                                if (e.key === 'Enter') saveEdit();
                            }}
                          />
                        </form>
                      ) : (
                        <span className="truncate block">{chat.title}</span>
                      )}
                    </div>
                  )}

                  {/* Hover Actions: Only show if not editing and not collapsed */}
                  {!isCollapsed && editingChatId !== chat.id && (
                    <div className="absolute right-2 opacity-0 group-hover:opacity-100 flex items-center gap-1 transition-opacity bg-[#0a0a0a]/80 backdrop-blur-sm rounded-lg p-0.5 shadow-xl">
                      <button 
                        onClick={(e) => startEditing(e, chat)}
                        className="p-1 hover:bg-white/10 rounded text-neutral-400 hover:text-white transition-colors"
                        title="Rename"
                      >
                        <Edit2 className="w-3 h-3" />
                      </button>
                      <button 
                        onClick={(e) => handleDelete(e, chat.id)}
                        className="p-1 hover:bg-red-500/20 rounded text-neutral-400 hover:text-red-400 transition-colors"
                        title="Delete"
                      >
                         <Trash2 className="w-3 h-3" />
                      </button>
                    </div>
                  )}
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      <div className="p-3 border-t border-white/10 flex flex-col gap-1">
        <button 
          onClick={onOpenIngest}
          className={cn("flex items-center gap-4 px-3 py-2.5 rounded-lg text-sm text-neutral-400 hover:text-white hover:bg-white/5 transition-colors group", isCollapsed && "justify-center px-0")}
          title="Ingest Knowledge"
        >
          <Upload className="w-4 h-4 group-hover:text-primary transition-colors" />
          {!isCollapsed && <span>Ingest Knowledge</span>}
        </button>
        <button 
          onClick={onOpenApiKeys}
          className={cn("flex items-center gap-4 px-3 py-2.5 rounded-lg text-sm text-neutral-400 hover:text-white hover:bg-white/5 transition-colors group", isCollapsed && "justify-center px-0")}
          title="API Keys"
        >
          <Key className="w-4 h-4 group-hover:text-primary transition-colors" />
          {!isCollapsed && <span>API Keys</span>}
        </button>
        <button 
          onClick={onOpenSettings}
          className={cn("flex items-center gap-4 px-3 py-2.5 rounded-lg text-sm text-neutral-400 hover:text-white hover:bg-white/5 transition-colors group", isCollapsed && "justify-center px-0")}
          title="Settings"
        >
          <Settings className="w-4 h-4 group-hover:text-primary transition-colors" />
          {!isCollapsed && <span>General Settings</span>}
        </button>

        <div className={cn("flex items-center gap-3 px-3 py-2 mt-2 rounded-lg text-xs text-neutral-600 border-t border-white/5 pt-3", isCollapsed && "justify-center px-0 border-none")}>
           <Cpu className="w-3 h-3" />
           {!isCollapsed && <span>Albot Core: v1.0</span>}
        </div>
      </div>
    </div>
  );
}
